INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-200', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast the political organization of the Aztec and Inca empires.', 'Similarities: both were large empires; both used tribute/labor systems; both had divine rulers; both expanded through conquest. Differences: Aztec system more decentralized (tribute from semi-autonomous states) vs Inca more centralized (direct provincial administration); different succession systems; Inca road network vs Aztec water-based transport; different approaches to incorporating conquered peoples. Top-band (13--15): explicit comparative analysis with detailed evidence.', 201);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-201', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the economic achievements of one pre-Columbian indigenous society.', 'Should address specific economic features: agriculture (chinampas/terracing), trade networks, tribute systems, labor organization, specialization. Should evaluate ''achievements'' --- sophistication, sustainability, ability to support large populations. Top-band answers use specific evidence and assess significance rather than merely describing.', 202);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-202', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, '"Indigenous societies in the Americas before 1500 were sophisticated and complex civilizations." To what extent do you agree?', 'Evidence of sophistication: urban planning (Tenochtitlan); engineering (Inca roads, irrigation); political systems (Iroquois Confederacy); agriculture (chinampas, terracing); cultural achievements (calendar, astronomy). Nuance: significant variation between societies; different measures of ''sophistication''; comparison with European standards may be misleading. Top-band answers address the complexity of the question and avoid Eurocentric framing.', 203);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-203', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the reasons for Spanish success and Aztec defeat in the conquest of Mexico.', 'Spanish advantages: superior weapons (steel, guns, horses); indigenous allies (Tlaxcalans); disease (smallpox); Cortes''s political skill. Aztec disadvantages: internal divisions; initial hesitation (Moctezuma); religious beliefs; disease devastation; siege of Tenochtitlan. Top-band answers evaluate the relative importance of these factors and avoid simplistic explanations.', 204);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-204', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Discuss the impact of the Columbian Exchange on the Americas and Europe.', 'Americas: devastating disease impact; introduction of horses and livestock transformed societies; new crops; displacement of indigenous agriculture. Europe: new food crops (potato, corn, tomato) improved nutrition; influx of gold/silver caused price revolution; new economic opportunities. Top-band answers address both regions and evaluate long-term significance.', 205);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-205', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, '"European treatment of indigenous populations was driven primarily by economic motives." To what extent do you agree?', 'Economic: encomienda for labor; mining; plantation agriculture; fur trade. Other motives: religious conversion; racial attitudes; legal frameworks (Law of Burgos, New Laws); some humanitarian voices (las Casas). Complexity: treatment varied by colonial power and period. Top-band answers evaluate the interplay of economic, religious, and ideological factors.', 206);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-206', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast political organization in Spanish America and British North America.', 'Spanish: centralized viceroyalty system; limited local autonomy; Council of the Indies; cabildos. British: greater local self-governance; colonial assemblies; salutary neglect; diverse colony types (royal, proprietary, charter). Similarities: both mercantilist; both had social hierarchies; both faced governance challenges. Top-band answers draw explicit comparisons with supporting evidence.', 207);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-207', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the impact of mercantilism on colonial economies in the Americas.', 'Impact: shaped trade patterns; created economic dependency; stimulated some economic growth (plantation agriculture, mining); restricted colonial manufacturing; created smuggling and black markets; different effects on different colonies. Top-band answers evaluate both positive and negative effects and compare across colonial systems.', 208);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-208', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, '"Colonial governments in the Americas served the interests of the mother country at the expense of colonial populations." To what extent do you agree?', 'Serving mother country: mercantilist trade restrictions; extraction of resources; taxation without representation; appointment of officials from Europe. Colonial benefits: infrastructure development; legal systems; trade connections; protection. Nuance: different experiences for different social groups; variation between colonial powers. Top-band answers evaluate the statement with reference to specific examples.', 209);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-209', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the impact of religious orders in Spanish America.', 'Positive impacts: education and healthcare; protection of indigenous peoples (some orders); cultural preservation (recording languages); Jesuit Reductions as model communities. Negative impacts: forced conversion; destruction of indigenous beliefs; collaboration with colonial system; cultural imperialism. Top-band answers evaluate both perspectives with specific evidence.', 210);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-210', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Discuss the reasons for the emergence of syncretism in the Americas.', 'Reasons: forced conversion left indigenous beliefs alive beneath surface; strategic adaptation by indigenous peoples; similarities between some beliefs; isolation of missions; limited clergy; indigenous agency in interpreting Christianity. Examples: Day of the Dead, Virgin of Guadalupe, Vodou, Candomble. Top-band answers explain the process of syncretism with specific examples.', 211);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-211', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Assess the role of Christianity in one colonial area: British, Spanish, or French.', 'Should address: role in justifying colonization; impact on indigenous peoples; influence on colonial governance; social and cultural effects; educational institutions; relationship between Church and State; extent of religious freedom. Top-band answers provide detailed analysis of one specific colonial context.', 212);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-212', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the importance of plantations in colonial American economies.', 'Importance: sugar, tobacco, cotton as major exports; drove demand for enslaved labor; generated enormous wealth; shaped colonial trade patterns; created planter aristocracy. Nuance: not all colonial economies were plantation-based; regional variations; long-term economic distortions; dependency on single crops. Top-band answers evaluate both the significance and the limitations of the plantation economy.', 213);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-213', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast the treatment of enslaved people in two colonial systems in the Americas.', 'Should compare legal frameworks, living conditions, family structures, paths to freedom, cultural autonomy, and forms of resistance across two systems (e.g., British vs Spanish, or French vs Portuguese). Top-band answers draw explicit comparisons and avoid simplistic generalizations.', 214);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-214', '1. Pre-Columbian & Colonial Americas', 'HL', 'short_answer', 'P3-AME', 15, '"Slave resistance was continuous and took many forms." Discuss with reference to the period 1500--1800.', 'Forms of resistance: everyday (work slowdowns, sabotage, feigning illness); cultural (maintaining African languages, music, religion); flight (maroon communities); revolts (Stono, Tacky''s, others); legal challenges. Top-band answers demonstrate the range and persistence of resistance while evaluating its effectiveness.', 215);

