INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-215', '2. Independence & Nation-Building', 'HL', 'short_answer', 'P3-AME', 15, '"Wars of Independence in the Americas were primarily caused by political grievances." To what extent do you agree with reference to one war of independence (1775--1824)?', 'Political: taxation without representation; restrictions on self-governance; colonial resentment of metropolitan control. Other factors: economic (mercantilist restrictions, trade grievances); intellectual (Enlightenment ideas, social contract); social (class tensions, Creole vs Peninsular). Top-band answers evaluate political against other factors for one specific independence movement.', 216);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-216', '2. Independence & Nation-Building', 'HL', 'short_answer', 'P3-AME', 15, 'Analyse the role of different social classes in the Wars of Independence in either the United States or Latin America.', 'Should address: which classes led the movement (elite, middle class); role of lower classes and their motivations; indigenous and enslaved peoples'' roles; class tensions within independence movements; whether independence changed class structures. Top-band answers analyze multiple classes and evaluate their relative contributions.', 217);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-217', '2. Independence & Nation-Building', 'HL', 'short_answer', 'P3-AME', 15, '"The Constitution of the United States was a revolutionary document for its time." To what extent do you agree?', 'Revolutionary: federalism; separation of powers; Bill of Rights; popular sovereignty; written constitution. Limitations: preserved slavery; limited suffrage (property-owning white males); Three-Fifths Compromise; Electoral College. Top-band answers evaluate what was revolutionary and what was conservative about the Constitution.', 218);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-218', '2. Independence & Nation-Building', 'HL', 'short_answer', 'P3-AME', 15, 'Examine the conditions that led to the establishment of caudillo rule in one Latin American country.', 'Conditions: weak institutions after independence; military''s role in liberation wars; regional divisions; ethnic/social fragmentation; economic instability; lack of democratic tradition; rural power structures. Top-band answers focus on one specific country with detailed examples.', 219);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-219', '2. Independence & Nation-Building', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the impact of independence on the economy of one country of the Americas.', 'Should address: disruption of colonial trade networks; new trading partnerships (especially with Britain); continued reliance on primary exports; foreign debt; land ownership patterns; infrastructure challenges; comparison with colonial economic structures. Top-band answers use specific economic data and evaluate both change and continuity.', 220);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-220', '2. Independence & Nation-Building', 'HL', 'short_answer', 'P3-AME', 15, '"Manifest Destiny was the most significant factor in US territorial expansion between 1800 and 1860." To what extent do you agree?', 'Manifest Destiny: ideological justification; popular support for expansion; racial superiority beliefs. Other factors: economic interests (land, resources, trade routes); strategic concerns; political ambitions; technology (railroads); specific events (Louisiana Purchase, Mexican-American War). Top-band answers evaluate Manifest Destiny against other factors.', 221);

