INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-543', '3. US Civil War', 'HL', 'P3-AME', 'The 13th Amendment:', 'Granted citizenship to all born in the US', 'Abolished slavery', 'Gave African American men the right to vote', 'Established Reconstruction', 1, 'See mark scheme for detailed explanation.', 544);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-544', '3. US Civil War', 'HL', 'P3-AME', 'Which battle is considered the turning point of the Civil War?', 'Bull Run', 'Antietam', 'Gettysburg', 'Shiloh', 2, 'See mark scheme for detailed explanation.', 545);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-545', '3. US Civil War', 'HL', 'P3-AME', 'Black Codes were designed to:', 'Grant freedom to enslaved people', 'Restrict the rights of freed African Americans', 'Punish Confederate leaders', 'Promote racial integration', 1, 'See mark scheme for detailed explanation.', 546);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-546', '3. US Civil War', 'HL', 'P3-AME', 'Reconstruction ended in:', '1865', '1870', '1873', '1877', 3, 'See mark scheme for detailed explanation.', 547);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-547', '3. US Civil War', 'HL', 'P3-AME', 'C | 2. B | 3. C | 4. B | 5. D', '', '', '', '', 2, 'See mark scheme for detailed explanation.', 548);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-221', '3. US Civil War', 'HL', 'short_answer', 'P3-AME', 15, 'Discuss the arguments for and against slavery in the US before the Civil War.', 'For slavery: economic arguments (plantation economy); states'' rights; racial ideology; biblical justifications; paternalism. Against: moral/religious arguments; Enlightenment principles; free labor ideology; abolitionist movement; political arguments about democracy. Top-band answers present both sides with specific evidence and analyze the intensity of the debate.', 222);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-222', '3. US Civil War', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the factors affecting the outcome of the Civil War.', 'Union advantages: industrial capacity; population; naval power; railroad network; Lincoln''s leadership. Confederate advantages: defensive strategy; military leadership; motivation. Key factors: Emancipation Proclamation; foreign relations; Union generals (Grant, Sherman); economic warfare. Top-band answers evaluate the relative importance of these factors.', 223);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-223', '3. US Civil War', 'HL', 'short_answer', 'P3-AME', 15, '"Reconstruction was a failure." To what extent do you agree?', 'Successes: 13th-15th Amendments; African American political participation; Freedmen''s Bureau; public education. Failures: Black Codes and Jim Crow; sharecropping; KKK violence; withdrawal of federal troops (1877); economic inequality persisted. Top-band answers evaluate different aspects and consider what ''success'' and ''failure'' mean in this context.', 224);

