INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-554', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'The Spanish-American War occurred in:', '1895', '1898', '1901', '1904', 1, 'See mark scheme for detailed explanation.', 555);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-555', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'The Roosevelt Corollary asserted the US right to:', 'Annex Latin American territory', 'Intervene in Latin American affairs', 'Establish a hemispheric parliament', 'Form military alliances with European powers', 1, 'See mark scheme for detailed explanation.', 556);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-556', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'The Panama Canal was completed in:', '1904', '1907', '1914', '1920', 2, 'See mark scheme for detailed explanation.', 557);
