INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-560', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'The Plan de Ayala called for:', 'Industrial modernization', 'Land redistribution to peasants', 'Religious reform', 'Military expansion', 1, 'See mark scheme for detailed explanation.', 561);
