INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-563', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'The Cristero War was fought over:', 'Land reform', 'Anti-clerical government policies', 'Oil nationalization', 'Foreign intervention', 1, 'See mark scheme for detailed explanation.', 564);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-564', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'Madero was overthrown by:', 'Zapata', 'Villa', 'Huerta', 'Obregon', 2, 'See mark scheme for detailed explanation.', 565);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-565', '4. Modern Americas (1865–1929)', 'HL', 'P3-AME', 'B | 2. C | 3. D | 4. B | 5. C', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 566);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-224', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast the processes of modernization in two countries of the Americas between 1865 and 1929.', 'Should compare: industrialization; urbanization; immigration; political development; social change; treatment of minorities/indigenous peoples. Top-band answers draw explicit analytical comparisons between two specific countries.', 225);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-225', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, '"Porfirio Diaz''s loss of political control was due to social inequality." To what extent do you agree?', 'Social inequality: concentration of land ownership; exploitation of peasants and workers; indigenous marginalization; growing middle class demands. Other factors: political repression; rigged elections; aging regime; economic crisis; opposition leaders (Madero, Zapata, Villa); US influence. Top-band answers evaluate social inequality against other factors.', 226);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-226', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the causes and consequences of immigration to one country of the Americas between 1865 and 1929.', 'Causes: push factors (poverty, persecution, war); pull factors (economic opportunity, land, religious freedom). Consequences: economic growth (labor force); cultural transformation; urbanization; social tensions (nativism, anti-immigration laws); political impact. Top-band answers address both causes and consequences with specific evidence.', 227);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-227', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the impact of US foreign policy on one Latin American country between 1880 and 1929.', 'Should address: specific US interventions; economic influence; political impact; social consequences; responses of the Latin American country. Top-band answers provide detailed analysis of one specific case study.', 228);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-228', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, '"The United States'' entry into World War I marked the end of American isolationism." To what extent do you agree?', 'For: decisive military intervention; Wilson''s global vision (Fourteen Points, League); economic engagement. Against: Senate rejected League; return to isolationism in 1920s; interventionism was limited to the Americas; economic vs political engagement. Top-band answers distinguish between different types of engagement and evaluate whether WWI truly ended isolationism.', 229);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-229', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, 'Examine the reasons for, and methods of, foreign intervention in the Mexican Revolution.', 'Reasons: protection of foreign (especially US) economic interests; border security; strategic concerns; ideological opposition. Methods: military intervention (Veracruz 1914, Pershing expedition 1916); diplomatic pressure; economic leverage; arms embargoes. Top-band answers examine both motivations and methods with specific evidence.', 230);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-230', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the social and economic impact of the Mexican Revolution on the peasantry.', 'Positive: land reform (especially under Cardenas); ejido system; constitutional protections; political inclusion; cultural recognition. Negative: limited and slow implementation; continued poverty; violence and displacement; urban bias of later governments. Top-band answers evaluate both achievements and limitations.', 231);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-231', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, '"The Mexican Revolution was primarily a struggle for land." To what extent do you agree?', 'Land issues: Zapata''s Plan de Ayala; hacienda system; Article 27; ejidos. Other issues: political reform (Madero); labor rights (Article 123); national sovereignty; anti-clericalism; regional power struggles; personal ambitions of leaders. Top-band answers evaluate land reform as one of several motivations.', 232);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-232', '4. Modern Americas (1865–1929)', 'HL', 'short_answer', 'P3-AME', 15, 'Assess the presidency of Lazaro Cardenas (1934--1940) and its significance for Mexico.', 'Achievements: massive land redistribution; oil nationalization; labor union support; educational expansion; institutional reform (PRM). Limitations: economic challenges of nationalization; authoritarian aspects; incomplete reforms; institutional party system limiting democracy. Top-band answers evaluate both the achievements and their limitations.', 233);

