INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-573', '5. Depression & World War II', 'HL', 'P3-AME', 'Lend-Lease was designed to:', 'Maintain US neutrality', 'Provide military aid to Allied nations', 'Contain Japanese expansion', 'Support Latin American development', 1, 'See mark scheme for detailed explanation.', 574);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-574', '5. Depression & World War II', 'HL', 'P3-AME', 'Japanese-American internment affected approximately:', '50,000 people', '90,000 people', '120,000 people', '200,000 people', 2, 'See mark scheme for detailed explanation.', 575);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-575', '5. Depression & World War II', 'HL', 'P3-AME', 'Canada entered WWII in:', '1937', '1939', '1941', '1942', 1, 'See mark scheme for detailed explanation.', 576);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-576', '5. Depression & World War II', 'HL', 'P3-AME', 'The Bracero Program involved:', 'Japanese-American relocation', 'Mexican agricultural workers in the US', 'Canadian military recruits', 'Brazilian industrial workers', 1, 'See mark scheme for detailed explanation.', 577);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-577', '5. Depression & World War II', 'HL', 'P3-AME', 'B | 2. B | 3. C | 4. B | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 578);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-233', '5. Depression & World War II', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the effectiveness of the New Deal in addressing the Great Depression in the United States.', 'Successes: banking reform; employment programs; Social Security; infrastructure; restored confidence. Limitations: did not end unemployment until WWII; opposition from business and Supreme Court; racial inequalities in implementation; expanded government power (controversial). Top-band answers evaluate different aspects and consider different perspectives on ''effectiveness.''', 234);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-234', '5. Depression & World War II', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast the impact of the Great Depression on two countries of the Americas.', 'Should address: economic impact (GDP decline, unemployment, trade collapse); social effects; political responses; recovery strategies. Top-band answers draw explicit comparisons between two specific countries with detailed evidence.', 235);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-235', '5. Depression & World War II', 'HL', 'short_answer', 'P3-AME', 15, '"The Great Depression caused more political change in Latin America than in North America." To what extent do you agree?', 'Latin America: regime changes; rise of populism; military interventions; ISI; new constitutions. North America: New Deal transformation but within existing system; Canadian welfare state beginnings; no regime change. Top-band answers compare the extent of political change across the two regions.', 236);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-236', '5. Depression & World War II', 'HL', 'short_answer', 'P3-AME', 15, 'Examine the economic effects of the Second World War on two countries of the Americas.', 'Should address: industrial expansion; employment; technological innovation; government spending; commodity prices; post-war economic position. Top-band answers compare two specific countries with detailed evidence.', 237);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-237', '5. Depression & World War II', 'HL', 'short_answer', 'P3-AME', 15, '"The United States'' path from neutrality to intervention was inevitable." To what extent do you agree?', 'Factors pushing toward intervention: FDR''s sympathies; Lend-Lease; Atlantic Charter; economic ties to Allies; Pearl Harbor. Factors against: strong isolationist sentiment; neutrality legislation; anti-war public opinion; America First Committee. Top-band answers evaluate the balance between interventionist and isolationist forces.', 238);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-238', '5. Depression & World War II', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the social impact of the Second World War on the home front in one country of the Americas.', 'Should address: women''s roles; racial minorities; civil liberties; cultural changes; demographic shifts; labor relations; government power expansion. Top-band answers provide detailed analysis of one country and evaluate the significance of wartime social changes.', 239);

