INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-590', '6. Post-War Americas (1945–1981)', 'HL', 'P3-AME', 'The Cuban Missile Crisis occurred in:', '1960', '1961', '1962', '1963', 2, 'See mark scheme for detailed explanation.', 591);
