INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-592', '6. Post-War Americas (1945–1981)', 'HL', 'P3-AME', 'SALT I was a product of:', 'Containment', 'Rollback', 'Detente', 'Brinkmanship', 2, 'See mark scheme for detailed explanation.', 593);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-593', '6. Post-War Americas (1945–1981)', 'HL', 'P3-AME', 'Operation Condor was coordinated by:', 'Central American governments', 'South American military dictatorships', 'Caribbean nations', 'North American intelligence agencies alone', 1, 'See mark scheme for detailed explanation.', 594);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-594', '6. Post-War Americas (1945–1981)', 'HL', 'P3-AME', 'Canada''s Cold War policy included:', 'NATO membership and NORAD', 'Neutrality', 'Alliance with the USSR', 'Isolation from international affairs', 0, 'See mark scheme for detailed explanation.', 595);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-595', '6. Post-War Americas (1945–1981)', 'HL', 'P3-AME', 'C | 2. B | 3. C | 4. B | 5. A', '', '', '', '', 2, 'See mark scheme for detailed explanation.', 596);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-239', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the contribution of social and cultural policies to Fidel Castro''s rule to 1980.', 'Social policies: literacy campaign; healthcare expansion; education reform; racial equality. Cultural: promotion of revolutionary culture; censorship and control. Assessment: improved social indicators but limited freedoms; achieved legitimacy through social gains. Top-band answers evaluate both achievements and costs.', 240);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-240', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, '"US intervention was the main obstacle to democratic development in Latin America between 1945 and 1980." Discuss.', 'US intervention: Guatemala (1954); Cuba (Bay of Pigs); Chile (1973); support for dictatorships; Alliance for Progress limitations. Other obstacles: military traditions; economic inequality; weak institutions; Cold War context; internal class conflicts. Top-band answers evaluate US role against domestic factors.', 241);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-241', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast the domestic policies of two authoritarian rulers in Latin America between 1945 and 1980.', 'Should compare economic policies, social programs, political repression, ideological orientation, and legacies. Top-band answers draw explicit analytical comparisons between two specific leaders.', 242);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-242', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast the domestic policies of Nixon and Ford.', 'Nixon: detente; environmental policy (EPA); wage-price controls; Southern strategy; Watergate. Ford: pardon of Nixon; economic challenges (stagflation); continuation of detente; limited domestic agenda. Similarities: both Republican; both faced economic difficulties; both dealt with Vietnam aftermath. Top-band answers draw explicit comparisons.', 243);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-243', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Discuss the reasons for the rise of nationalism in Quebec.', 'Reasons: historical grievances; linguistic and cultural identity; economic disparities; Quiet Revolution''s secularization; federal language policies; FLQ crisis; Parti Quebecois; influence of global decolonization movements. Top-band answers analyze multiple causes and their interconnections.', 244);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-244', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Examine the social and cultural impact of the Cold War on the US during Truman''s presidency.', 'Impact: McCarthyism and Red Scare; loyalty oaths; Hollywood blacklist; nuclear anxiety; civil defense programs; impact on education and science; suburban development; conformity culture; impact on civil rights movement. Top-band answers evaluate multiple dimensions of Cold War impact.', 245);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-245', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the impact of the Cold War on one Latin American country between 1945 and 1981.', 'Should address: US intervention; political polarization; economic policies; human rights impact; military governments; social movements. Top-band answers provide detailed analysis of one specific country.', 246);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-246', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, '"The Cuban Missile Crisis was the most dangerous moment of the Cold War." To what extent do you agree?', 'Supporting: closest to nuclear war; direct superpower confrontation; 13 days of crisis; nuclear weapons on US doorstep. Against: other crises also dangerous (Berlin, Korea); crisis was resolved peacefully; both sides showed restraint; established hotline and better communication. Top-band answers evaluate the Crisis''s danger in comparison with other Cold War moments.', 247);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-247', '6. Post-War Americas (1945–1981)', 'HL', 'short_answer', 'P3-AME', 15, 'Discuss the reasons for, and characteristics of, Eisenhower''s New Look policy.', 'Reasons: desire to reduce military spending; nuclear deterrence as cheaper option; Korean War experience; domestic economic priorities. Characteristics: massive retaliation doctrine; nuclear weapons emphasis; covert operations (CIA); alliances and containment. Top-band answers evaluate both the rationale and the implementation.', 248);

