INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-598', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'Cesar Chavez organized:', 'Factory workers', 'Agricultural workers', 'Miners', 'Railroad workers', 1, 'See mark scheme for detailed explanation.', 599);
