INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-600', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'The 1960s counter-culture movement was characterized by:', 'Support for traditional values', 'Anti-war activism and social experimentation', 'Pro-business ideology', 'Religious revivalism', 1, 'See mark scheme for detailed explanation.', 601);
