INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-602', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'NAFTA came into effect in:', '1990', '1992', '1994', '1996', 2, 'See mark scheme for detailed explanation.', 603);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-603', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'The Quebec sovereignty referendum of 1995 resulted in:', 'A clear victory for sovereignty', 'A narrow defeat for sovereignty', 'A large majority against sovereignty', 'A tie requiring a re-vote', 1, 'See mark scheme for detailed explanation.', 604);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-604', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'The Iran-Contra affair involved:', 'Arms sales to Iran funding Nicaraguan rebels', 'Secret trade with Cuba', 'Canadian espionage', 'Mexican border disputes', 0, 'See mark scheme for detailed explanation.', 605);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-605', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'The Falklands War was between:', 'Chile and Peru', 'Argentina and Britain', 'Brazil and Paraguay', 'Venezuela and Colombia', 1, 'See mark scheme for detailed explanation.', 606);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-606', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'Hugo Chavez came to power in:', '1989', '1995', '1999', '2003', 2, 'See mark scheme for detailed explanation.', 607);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-607', '7. Civil Rights & Contemporary', 'HL', 'P3-AME', 'C | 2. B | 3. A | 4. B | 5. C', '', '', '', '', 2, 'See mark scheme for detailed explanation.', 608);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-248', '7. Civil Rights & Contemporary', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the effectiveness of nonviolent protest in the US civil rights movement.', 'Effective: moral authority; media attention (Birmingham, Selma); legislative achievements; building broad coalitions; international support. Limitations: slow pace of change; violence against protesters; northern racism harder to address; economic inequality persisted; rise of Black Power as alternative. Top-band answers evaluate both effectiveness and limitations.', 249);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-249', '7. Civil Rights & Contemporary', 'HL', 'short_answer', 'P3-AME', 15, 'Compare and contrast two civil rights or social movements in the Americas post-1945.', 'Should compare: causes/grievances; methods; leadership; achievements; obstacles; legacy. Top-band answers draw explicit analytical comparisons between two specific movements.', 250);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-250', '7. Civil Rights & Contemporary', 'HL', 'short_answer', 'P3-AME', 15, '"The civil rights legislation of the 1960s solved the problem of racial discrimination in the United States." To what extent do you agree?', 'Achievements: legal desegregation; voting rights; employment protection; cultural change. Limitations: de facto segregation persisted; economic inequality; institutional racism; white backlash; need for continued activism. Top-band answers evaluate both the significance and the limitations of legislation.', 251);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-251', '7. Civil Rights & Contemporary', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the domestic policies of President Reagan.', 'Policies: tax cuts; deregulation; reduced social spending; military buildup; anti-union (PATCO). Assessment: economic growth but increased inequality; deficit spending; conservative cultural shift; HIV/AIDS response criticized. Top-band answers evaluate both supporters'' and critics'' perspectives.', 252);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-252', '7. Civil Rights & Contemporary', 'HL', 'short_answer', 'P3-AME', 15, 'Discuss the challenges faced by Latin American countries in their transitions to democracy after 1980.', 'Challenges: dealing with past human rights abuses; economic crises (debt crisis); social inequality; institutional weakness; military influence; corruption; drug trafficking; external pressures (neoliberalism). Top-band answers discuss multiple challenges with specific country examples.', 253);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-253', '7. Civil Rights & Contemporary', 'HL', 'short_answer', 'P3-AME', 15, 'Evaluate the impact of NAFTA on the economies of its member states.', 'Positive: increased trade; foreign investment; economic integration; lower consumer prices. Negative: job losses in certain sectors; environmental concerns; inequality within countries; Mexican agricultural displacement. Top-band answers evaluate impact on all three member states and consider multiple perspectives.', 254);

