INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-614', '1. Medieval Europe (750–1500)', 'HL', 'P3-EUR', 'Approximately what proportion of Europe''s population died in the Black Death (1347--1351)?', 'One-tenth', 'One-quarter', 'One-third', 'One-half', 2, 'See mark scheme for detailed explanation.', 615);
