INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-617', '1. Medieval Europe (750–1500)', 'HL', 'P3-EUR', 'The three-field system improved agriculture by:', 'Introducing new crops from Asia', 'Rotating crops and leaving one field fallow', 'Using irrigation canals', 'Replacing animal labor with water mills', 1, 'See mark scheme for detailed explanation.', 618);
