INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-620', '1. Medieval Europe (750–1500)', 'HL', 'P3-EUR', 'Pope Urban II called the First Crusade at which council?', 'Council of Nicaea', 'Council of Clermont', 'Council of Trent', 'Fourth Lateran Council', 1, 'See mark scheme for detailed explanation.', 621);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-621', '1. Medieval Europe (750–1500)', 'HL', 'P3-EUR', 'The Battle of Hattin (1187) resulted in:', 'Crusader capture of Damascus', 'Saladin''s recapture of Jerusalem', 'The founding of the Templars', 'The fall of Constantinople', 1, 'See mark scheme for detailed explanation.', 622);
