INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-624', '1. Medieval Europe (750–1500)', 'HL', 'P3-EUR', 'Which Italian city-states benefited most economically from the Crusades?', 'Rome and Naples', 'Venice and Genoa', 'Florence and Milan', 'Turin and Palermo', 1, 'See mark scheme for detailed explanation.', 625);
