INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-254', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, '"The power of medieval monarchs was always limited by the Church." To what extent do you agree with this statement with reference to the period 750--1500?', 'Answers should consider: the Investiture Controversy as a key example of Church limiting royal power; Magna Carta and baronial constraints; the role of papal coronation in legitimizing rulers; counter-arguments including strong monarchs who dominated the Church (e.g., Henry VIII predecessors, Philip IV of France vs Boniface VIII); the Avignon Papacy as evidence of royal dominance over the Church. Top-band answers (13--15) will offer a balanced, well-supported argument with specific examples and a clear thesis addressing ''to what extent.'' Mid-band (10--12) will have relevant knowledge but may lack balance or depth. Lower band (7--9) will be largely narrative with limited analysis.', 255);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-255', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, 'Compare and contrast the political development of England and France between 1000 and 1500.', 'Similarities: both experienced centralization of royal authority; feudal structures; conflicts between monarchy and nobility; impact of the Hundred Years'' War. Differences: England developed parliamentary institutions earlier (Magna Carta, Model Parliament 1295); France had a more absolutist trajectory; different relationships with the papacy; England''s common law vs France''s Roman law tradition. Top-band answers will use specific examples (e.g., William I''s Domesday Book, Philip II Augustus''s expansion) and draw analytical comparisons rather than simply describing each country separately.', 256);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-256', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the significance of the Investiture Controversy for the development of European politics.', 'Key points: established a precedent for limits on both papal and secular authority; the Concordat of Worms (1122) as a compromise; long-term impact on Church-State relations; contributed to the development of the concept of separate spheres of authority; weakened the Holy Roman Empire internally. Top-band answers will assess ''significance'' by weighing short-term vs long-term effects and comparing with other factors shaping European politics.', 257);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-257', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, '"The Black Death was the most significant turning point in medieval European society." To what extent do you agree?', 'For: massive demographic change; labor shortages raised wages and challenged serfdom; accelerated decline of feudalism; psychological/cultural impact; contributed to peasant revolts. Against: other factors also important (Commercial Revolution, urbanization, technological change predated plague); impact varied by region; feudalism was already weakening; recovery was uneven. Top-band answers address ''most significant'' by weighing against other turning points. Mid-band answers may describe effects without fully evaluating significance.', 258);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-258', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the reasons for the decline of feudalism in Europe between 1000 and 1400.', 'Reasons include: growth of towns and trade creating alternatives to agricultural labor; the Black Death''s demographic impact; rise of money economy replacing land-based obligations; peasant revolts; centralization of royal authority; Crusades exposing Europeans to different systems. Top-band answers will prioritize and evaluate the relative importance of multiple factors, using specific examples.', 259);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-259', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the social and economic impact of the growth of towns in medieval Europe.', 'Economic: new centers of trade and craft production; rise of merchant class; development of banking and credit; market economy. Social: new social classes (bourgeoisie); challenge to feudal hierarchy; greater personal freedom for urban dwellers; guild system; cultural developments. Top-band answers discuss both positive effects and tensions/challenges (e.g., urban poverty, conflicts with feudal lords).', 260);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-260', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, '"Religious motivation was the primary cause of the Crusades." To what extent do you agree with this statement?', 'Religious factors: papal call for holy war; promise of remission of sins; pilgrimage tradition; desire to recapture Holy Land. Other factors: political ambitions of rulers; younger sons seeking land; economic opportunities (trade routes); adventure and glory; Byzantine appeal for help. Top-band answers will weigh religious against other motivations with specific examples and arrive at a balanced judgment. They should note that motivations varied by Crusade and by participant.', 261);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-261', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the consequences of the Crusades for Europe and the Middle East.', 'For Europe: expanded trade (especially for Italian cities); transfer of knowledge (medicine, mathematics, navigation); strengthened then weakened papal authority; development of military orders; cultural exchange. For Middle East: political consolidation under leaders like Saladin; destruction and displacement; eventual Muslim reconquest; lasting suspicion of Western intentions. Top-band answers address consequences for both regions and distinguish short-term from long-term effects.', 262);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-262', '1. Medieval Europe (750–1500)', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the reasons for the failure of the Crusader States between 1100 and 1291.', 'Reasons: internal divisions among Crusader states; Muslim unification under Zengi, Nur al-Din, and Saladin; distance from European reinforcements; declining enthusiasm for Crusading in Europe; strategic overextension; failure of later Crusades to achieve goals; economic strain. Top-band answers will evaluate relative importance of factors and use specific events as evidence.', 263);

