INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-632', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'The Treaty of Tordesillas (1494) divided the world between:', 'England and France', 'Spain and Portugal', 'The Netherlands and Spain', 'Portugal and the Ottoman Empire', 1, 'See mark scheme for detailed explanation.', 633);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-633', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'Vasco da Gama reached India by sea in:', '1488', '1492', '1498', '1502', 2, 'See mark scheme for detailed explanation.', 634);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-634', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'The Columbian Exchange refers to:', 'Columbus''s trade agreements with indigenous peoples', 'The transfer of plants, animals, and diseases between Old and New Worlds', 'Economic competition between European powers', 'The exchange of prisoners during colonial wars', 1, 'See mark scheme for detailed explanation.', 635);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-635', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'Mercantilism emphasized:', 'Free trade between nations', 'Accumulation of gold and silver through trade surpluses', 'Agricultural self-sufficiency', 'International cooperation', 1, 'See mark scheme for detailed explanation.', 636);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-636', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'Which disease had the most devastating impact on indigenous American populations?', 'Bubonic plague', 'Malaria', 'Smallpox', 'Typhoid', 2, 'See mark scheme for detailed explanation.', 637);
