INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-638', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'Martin Luther posted his 95 Theses in:', '1509', '1517', '1521', '1534', 1, 'See mark scheme for detailed explanation.', 639);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-639', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'The Peace of Augsburg (1555) established the principle of:', 'Religious tolerance for all faiths', 'Cuius regio, eius religio', 'Papal supremacy over princes', 'Universal Calvinism in Germany', 1, 'See mark scheme for detailed explanation.', 640);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-640', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'The Council of Trent (1545--1563) was part of the:', 'Protestant Reformation', 'Counter-Reformation', 'Scientific Revolution', 'Thirty Years'' War peace process', 1, 'See mark scheme for detailed explanation.', 641);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-641', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'The Peace of Westphalia (1648) is significant because it:', 'Reunited Catholic and Protestant churches', 'Established the principle of state sovereignty', 'Created the Holy Roman Empire', 'Ended the Ottoman threat to Europe', 1, 'See mark scheme for detailed explanation.', 642);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-642', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'The Jesuits were founded by:', 'Martin Luther', 'John Calvin', 'Ignatius of Loyola', 'Thomas More', 2, 'See mark scheme for detailed explanation.', 643);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-643', '2. Renaissance & Reformation', 'HL', 'P3-EUR', 'B | 2. B | 3. B | 4. B | 5. C', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 644);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-263', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, '"The wealth of Italian cities was the most significant factor in the development of the Renaissance." To what extent do you agree?', 'For: trade wealth of Venice, Florence, Genoa funded patronage; banking families (Medici) supported artists; economic prosperity enabled leisure for intellectual pursuits. Against: classical heritage and proximity to Roman ruins; political competition between city-states; humanism as an intellectual movement; role of the Church; impact of the Black Death creating social change. Top-band answers evaluate multiple factors and reach a supported judgment about relative significance.', 264);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-264', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, 'Compare and contrast the Italian Renaissance and the Northern Renaissance.', 'Similarities: revival of classical learning; emphasis on humanism; patronage systems; artistic innovation. Differences: Italian focus on classical forms vs Northern focus on Christian humanism; Italian secular themes vs Northern religious themes; different artistic styles (idealized vs realistic); different social contexts (Italian city-states vs Northern monarchies); timing (Italian earlier, Northern later). Top-band answers will draw explicit analytical comparisons, not just describe each separately.', 265);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-265', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the impact of the printing press on European society and culture.', 'Impact: democratization of knowledge; spread of Renaissance ideas; facilitated the Reformation (Luther''s theses); increased literacy; standardization of languages; growth of vernacular literature; challenged Church monopoly on knowledge; scientific communication. Limitations: slow initial adoption; high illiteracy rates persisted; Church attempted censorship (Index of Forbidden Books). Top-band answers will assess both the extent and limitations of the printing press''s impact.', 266);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-266', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, 'Compare and contrast Spanish and Portuguese motives for exploration up to 1550.', 'Similarities: both sought new trade routes; both had religious motivations (spreading Christianity); both sought gold and wealth; both received papal sanction. Differences: Portugal focused on Africa and Asia (spice trade); Spain focused on the Americas; different colonial models; Portuguese emphasis on trading posts vs Spanish territorial conquest; different relationships with indigenous populations. Top-band answers provide specific comparative analysis with evidence.', 267);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-267', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the economic impact on Europe of the voyages of exploration.', 'Positive impacts: new trade routes and commodities; price revolution from influx of precious metals; rise of Atlantic economies; development of banking and joint-stock companies; growth of mercantilism. Negative/complex impacts: inflation; shift of economic power from Mediterranean to Atlantic; exploitation and slavery; uneven distribution of wealth; dependence on colonial resources. Top-band answers will evaluate both positive and negative consequences with specific examples.', 268);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-268', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, '"European exploration was driven primarily by economic motives." To what extent do you agree?', 'Economic motives: desire for spices and luxury goods; search for gold; new trade routes after Ottoman expansion; mercantilism. Other motives: religious (spreading Christianity, Reconquista spirit); technological (new navigation tools, caravel); political (national prestige, competition between states); intellectual curiosity. Top-band answers weigh economic against other factors and note that motives varied by country and time period.', 269);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-269', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the reasons for criticism of the Catholic Church at the start of the 16th century.', 'Reasons: sale of indulgences; corruption and worldliness of clergy; absenteeism and pluralism; papal extravagance; lack of education among lower clergy; theological criticisms (humanism''s influence); printing press spreading dissent; political rulers resenting papal interference and taxation. Top-band answers distinguish between theological, institutional, and political criticisms and evaluate their relative importance.', 270);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-270', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, '"The Thirty Years'' War was primarily a religious conflict." To what extent do you agree?', 'Religious factors: Protestant-Catholic tensions in Holy Roman Empire; Defenestration of Prague; initial Bohemian revolt. Political/other factors: Habsburg vs Bourbon rivalry; Swedish and Danish intervention for strategic reasons; French (Catholic) allying with Protestants; dynastic ambitions; constitutional issues within the Empire. Top-band answers show how the war evolved from religious to political over its four phases (Bohemian, Danish, Swedish, French) and reach a balanced conclusion.', 271);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-271', '2. Renaissance & Reformation', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the view that the Scientific Revolution overturned accepted belief systems.', 'For: Copernican heliocentrism challenged geocentric model; Galileo''s observations contradicted Church teachings; Newton''s laws offered mechanical explanations; scientific method prioritized empirical evidence over authority. Against: many scientists remained religious; Church was not uniformly opposed; change was gradual not sudden; impact limited to educated elites initially; coexistence of old and new ideas. Top-band answers address the nuance of ''overturned'' and evaluate the extent and pace of change.', 272);

