INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-645', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'Montesquieu advocated:', 'Absolute monarchy', 'Separation of powers', 'Direct democracy', 'Theocratic government', 1, 'See mark scheme for detailed explanation.', 646);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-646', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'Which of the following was NOT considered an enlightened despot?', 'Frederick the Great', 'Catherine the Great', 'Joseph II of Austria', 'Louis XIV of France', 3, 'See mark scheme for detailed explanation.', 647);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-647', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'The Glorious Revolution (1688) in England resulted in:', 'Absolute monarchy being strengthened', 'A constitutional monarchy with parliamentary power', 'The execution of the king', 'A French invasion', 1, 'See mark scheme for detailed explanation.', 648);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-648', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'Rousseau''s key contribution to political philosophy was:', 'The theory of mercantilism', 'The social contract and popular sovereignty', 'The divine right of kings', 'Scientific method', 1, 'See mark scheme for detailed explanation.', 649);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-649', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'B | 2. B | 3. D | 4. B | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 650);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-650', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'The Estates-General was convened in:', '1787', '1789', '1791', '1793', 1, 'See mark scheme for detailed explanation.', 651);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-651', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'The Reign of Terror was led by:', 'Louis XVI', 'Napoleon Bonaparte', 'Maximilien Robespierre', 'Marquis de Lafayette', 2, 'See mark scheme for detailed explanation.', 652);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-652', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'The Napoleonic Code is significant because it:', 'Restored feudal privileges', 'Established equality before the law', 'Created a democratic constitution', 'Abolished private property', 1, 'See mark scheme for detailed explanation.', 653);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-653', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'Napoleon''s invasion of Russia failed primarily due to:', 'British naval intervention', 'Scorched-earth tactics and winter conditions', 'A popular uprising in France', 'Ottoman military support for Russia', 1, 'See mark scheme for detailed explanation.', 654);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-654', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'The Congress of Vienna aimed to:', 'Spread revolutionary ideals across Europe', 'Restore the balance of power and conservative order', 'Create a democratic European federation', 'Abolish monarchy throughout Europe', 1, 'See mark scheme for detailed explanation.', 655);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-655', '3. Absolutism & Revolution', 'HL', 'P3-EUR', 'B | 2. C | 3. B | 4. B | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 656);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-272', '3. Absolutism & Revolution', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the extent to which Louis XIV was a successful absolute monarch.', 'Successes: centralized government; controlled nobility through Versailles; strengthened military; cultural patronage; revocation of Edict of Nantes showed religious authority. Failures: costly wars (War of Spanish Succession); financial problems; persecution of Huguenots harmed economy; left France in debt; popular suffering. Top-band answers weigh successes against failures and consider different criteria for ''success'' (political control vs national welfare).', 273);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-273', '3. Absolutism & Revolution', 'HL', 'short_answer', 'P3-EUR', 15, '"Enlightened despotism was a contradiction in terms." To what extent do you agree?', 'Contradiction argument: reforms served to strengthen monarchy not liberate people; reforms could be revoked; no genuine sharing of power; limited impact on peasant life. Counter-argument: genuine reforms in education, law, religious tolerance; modernization of administration; some rulers genuinely influenced by Enlightenment ideals; reform from above as the only practical option. Top-band answers use specific examples (Frederick II, Catherine II, Joseph II) and reach a nuanced conclusion.', 274);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-274', '3. Absolutism & Revolution', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the impact of Enlightenment ideas on European politics by 1800.', 'Impact: influenced American and French Revolutions; concepts of natural rights, social contract, separation of powers; challenge to absolute monarchy and divine right; religious tolerance; legal reform; growth of public sphere and critical press. Limitations: limited to educated elites; many rulers resisted change; Enlightenment thinkers often disagreed; practical implementation was uneven. Top-band answers assess both the extent and limitations of Enlightenment influence.', 275);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-275', '3. Absolutism & Revolution', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the social and economic impact of the Revolution in France.', 'Social: abolition of feudal privileges; Declaration of Rights; new social mobility; impact on women; de-Christianization campaign; Terror''s social consequences. Economic: redistribution of Church and noble lands; assignats and inflation; disruption of trade; abolition of guilds and internal tariffs; continental system. Top-band answers discuss both positive and negative impacts and consider different social groups'' experiences.', 276);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-276', '3. Absolutism & Revolution', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the reasons for Napoleon''s military defeat.', 'Reasons: Russian campaign disaster (1812); overextension of empire; coalition warfare; British naval supremacy (Trafalgar); Continental System''s failure; national resistance movements (Spain, Germany); internal French war-weariness; strategic errors at Waterloo. Top-band answers evaluate the relative importance of multiple factors and distinguish between long-term weaknesses and immediate causes of defeat.', 277);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-277', '3. Absolutism & Revolution', 'HL', 'short_answer', 'P3-EUR', 15, '"The French Revolution brought more change than continuity to France." To what extent do you agree?', 'Change: end of absolute monarchy; abolition of feudalism; new legal code; secularization; new political culture; social mobility. Continuity: centralized state persisted; social inequality remained; authoritarianism (Napoleon); restoration of monarchy after 1815; limited gains for women and lower classes. Top-band answers weigh specific areas of change against continuity and reach a nuanced judgment.', 278);

