INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-657', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'Metternich was primarily associated with:', 'Promoting liberal nationalism', 'Suppressing revolutionary movements', 'Unifying Germany', 'Establishing democracy in Austria', 1, 'See mark scheme for detailed explanation.', 658);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-658', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'The Franco-Prussian War (1870--1871) resulted in:', 'French victory and territorial gains', 'German unification under Prussia', 'Austrian dominance of Central Europe', 'British intervention on the continent', 1, 'See mark scheme for detailed explanation.', 659);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-659', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'The Paris Commune of 1871 was:', 'A conservative monarchist government', 'A radical socialist revolutionary government', 'A Prussian occupation administration', 'A liberal democratic reform movement', 1, 'See mark scheme for detailed explanation.', 660);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-660', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'The Concert of Europe was designed to:', 'Promote nationalist movements', 'Maintain the post-Napoleonic balance of power', 'Expand European colonial empires', 'Create a European parliament', 1, 'See mark scheme for detailed explanation.', 661);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-661', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'B | 2. B | 3. B | 4. B | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 662);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-662', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'Cavour''s key strategy for Italian unification was:', 'Popular revolution', 'Diplomatic alliance with France', 'Military conquest alone', 'Papal support', 1, 'See mark scheme for detailed explanation.', 663);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-663', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'The Zollverein was:', 'A military alliance', 'A customs union', 'A constitution', 'A political party', 1, 'See mark scheme for detailed explanation.', 664);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-664', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'Bismarck unified Germany through three wars. Which was NOT one of them?', 'Danish War (1864)', 'Austro-Prussian War (1866)', 'Franco-Prussian War (1870--71)', 'Russo-Prussian War (1877)', 3, 'See mark scheme for detailed explanation.', 665);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-665', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'Garibaldi''s Expedition of the Thousand conquered:', 'Lombardy and Venetia', 'Sicily and Southern Italy', 'Rome and the Papal States', 'Austria and Tyrol', 1, 'See mark scheme for detailed explanation.', 666);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-666', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'The Kulturkampf was directed against:', 'Socialists', 'The Catholic Church', 'The Prussian aristocracy', 'Polish nationalists', 1, 'See mark scheme for detailed explanation.', 667);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-667', '4. 19th Century Nationalism', 'HL', 'P3-EUR', 'B | 2. B | 3. D | 4. B | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 668);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-278', '4. 19th Century Nationalism', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the causes and consequences of the 1848 to 1849 Revolutions in two European countries.', 'Causes: economic crisis; liberal and nationalist aspirations; social inequality; inspiration from the February Revolution in France. Consequences vary by country but may include: brief constitutional gains; ultimate conservative reaction and restoration; growth of nationalist movements; impact on future unification movements. Top-band answers compare two specific cases (e.g., France and the German states, or the Austrian Empire and Italy) with detailed knowledge.', 279);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-279', '4. 19th Century Nationalism', 'HL', 'short_answer', 'P3-EUR', 15, '"Nationalism was the most powerful force in European politics in the 19th century." To what extent do you agree?', 'For: drove Italian and German unification; independence movements in Greece, Belgium, Balkans; 1848 Revolutions; shaped diplomatic alignments. Against: conservatism remained powerful (Concert of Europe, Metternich system); liberalism also drove political change; industrialization transformed society; imperialism and economic factors; class conflict (socialism). Top-band answers evaluate nationalism against other forces and note that nationalism itself took different forms.', 280);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-280', '4. 19th Century Nationalism', 'HL', 'short_answer', 'P3-EUR', 15, 'Compare and contrast the policies of Louis XVIII and Charles X.', 'Louis XVIII: constitutional charter (1814); moderate royalist; attempted to balance old regime supporters and post-revolutionary interests; accepted constitutional limits. Charles X: ultra-royalist; attempted to restore absolute authority; passed repressive laws; July Ordinances provoked revolution (1830). Similarities: both Bourbons; both faced challenges of governing post-revolutionary France; both had to manage competing factions. Top-band answers draw explicit comparisons and assess effectiveness.', 281);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-281', '4. 19th Century Nationalism', 'HL', 'short_answer', 'P3-EUR', 15, '"Bismarck was the most important factor in the unification of Germany." Discuss with reference to the period up to 1871.', 'For Bismarck: diplomatic skill; manipulation of wars; Ems Dispatch; realpolitik; relationship with Wilhelm I. Other factors: Zollverein and economic integration; nationalism and liberal movements; Prussian military strength; Austrian weakness; French defeat; role of the 1848 Revolutions in shaping nationalism. Top-band answers evaluate Bismarck''s role against other factors and reach a supported judgment.', 282);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-282', '4. 19th Century Nationalism', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the causes and consequences of the 1848 to 1849 Revolutions in Italy.', 'Causes: Austrian dominance; nationalist aspirations; liberal demands; economic hardship; inspiration from French revolution. Consequences: failure of revolution; Austrian control reasserted; lesson that foreign help needed; radicalization of some nationalists; Piedmont-Sardinia emerged as leader of future unification. Top-band answers provide specific evidence and evaluate both short-term failure and long-term consequences.', 283);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-283', '4. 19th Century Nationalism', 'HL', 'short_answer', 'P3-EUR', 15, 'Compare and contrast the roles of Cavour and Bismarck in achieving national unification.', 'Similarities: both used diplomacy and war; both were pragmatic realists (realpolitik); both used alliances strategically; both were dominant political figures. Differences: Cavour relied more on diplomacy and French alliance; Bismarck more on military power; different relationships with popular nationalism; different political systems (constitutional vs authoritarian); Cavour died before unification completed. Top-band answers draw explicit analytical comparisons.', 284);

