INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-669', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'Bloody Sunday (1905) involved:', 'The assassination of the Tsar', 'Troops firing on peaceful demonstrators', 'A Bolshevik uprising', 'A military mutiny', 1, 'See mark scheme for detailed explanation.', 670);
