INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-671', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'War Communism included:', 'Limited private enterprise', 'Grain requisitioning and nationalization', 'Land redistribution to peasants', 'Foreign investment incentives', 1, 'See mark scheme for detailed explanation.', 672);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-672', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'The NEP was introduced because:', 'Lenin wanted to fully implement communism', 'War Communism had devastated the economy', 'Foreign powers demanded it', 'The Duma passed legislation requiring it', 1, 'See mark scheme for detailed explanation.', 673);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-673', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'B | 2. B | 3. C | 4. B | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 674);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-674', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'The assassination of Archduke Franz Ferdinand occurred in:', 'Belgrade', 'Vienna', 'Sarajevo', 'Berlin', 2, 'See mark scheme for detailed explanation.', 675);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-675', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'The Schlieffen Plan failed because:', 'Italy joined the Entente', 'Russia mobilized faster than expected and Belgium resisted', 'France surrendered quickly', 'The United States intervened immediately', 1, 'See mark scheme for detailed explanation.', 676);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-676', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'Which battle symbolized the horror of trench warfare with over 1 million casualties?', 'Battle of Marne', 'Battle of Verdun', 'Battle of the Somme', 'Battle of Tannenberg', 2, 'See mark scheme for detailed explanation.', 677);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-677', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'The United States entered WWI in:', '1914', '1915', '1916', '1917', 3, 'See mark scheme for detailed explanation.', 678);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-678', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'Which was NOT a long-term cause of WWI?', 'Alliance system', 'Imperial rivalries', 'Assassination of Franz Ferdinand', 'Arms race', 2, 'See mark scheme for detailed explanation.', 679);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-679', '5. Imperial Russia & World War I', 'HL', 'P3-EUR', 'C | 2. B | 3. C | 4. D | 5. C', '', '', '', '', 2, 'See mark scheme for detailed explanation.', 680);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-284', '5. Imperial Russia & World War I', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the view that the Provisional Government collapsed because of the power of the Soviets.', 'Role of Soviets: dual power arrangement; Soviet Order No. 1 undermining military discipline; Soviets had popular legitimacy; Petrograd Soviet controlled key infrastructure. Other factors: Provisional Government''s decision to continue war; failure to address land reform; Kornilov Affair; economic crisis; Lenin''s leadership and Bolshevik organization. Top-band answers evaluate the relative importance of Soviet power against other factors.', 285);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-285', '5. Imperial Russia & World War I', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the significance of the 1905 Revolution for the political development of Russia.', 'Significance: forced constitutional concessions (October Manifesto, Duma); revealed weaknesses of tsarist system; demonstrated power of mass action; created precedent for 1917; formation of soviets. Limitations: Tsar retained autocratic power through Fundamental Laws; Duma was weak; reforms were limited; revolution was suppressed. Top-band answers assess both what changed and what remained the same.', 286);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-286', '5. Imperial Russia & World War I', 'HL', 'short_answer', 'P3-EUR', 15, '"The First World War was the main cause of the February Revolution in Russia in 1917." To what extent do you agree?', 'War factors: military defeats; economic strain; food shortages; loss of life; discrediting of Tsar''s military leadership. Other factors: long-term social inequality; failure of earlier reforms; weakness of the Duma; revolutionary movements; political repression; Rasputin''s influence. Top-band answers weigh war as a catalyst against deeper structural causes and reach a balanced conclusion.', 287);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-287', '5. Imperial Russia & World War I', 'HL', 'short_answer', 'P3-EUR', 15, '"The Alliance system was the most important cause of the First World War." To what extent do you agree?', 'Alliance system: transformed bilateral disputes into general war; created a rigid framework; automatic mobilization plans. Other causes: imperial rivalries (Morocco crises, Balkans); militarism and arms race; nationalism (particularly Balkan); economic competition; specific triggers (assassination, July Crisis). Top-band answers evaluate the alliance system against other long-term and short-term causes and reach a balanced judgment.', 288);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-288', '5. Imperial Russia & World War I', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the factors leading to the defeat of Germany and the other Central Powers in 1918.', 'Factors: US entry providing fresh troops and resources; Allied blockade causing economic hardship; failure of Spring Offensive (1918); internal collapse (mutinies, revolution); Allied use of new technologies (tanks); strategic overextension; collapse of Ottoman and Austro-Hungarian allies. Top-band answers evaluate the relative importance of military, economic, and domestic factors.', 289);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-289', '5. Imperial Russia & World War I', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the impact of the First World War on civilian populations in two European countries.', 'Should discuss: rationing and food shortages; conscription''s impact on families; women entering workforce; propaganda and censorship; economic hardship; psychological impact; civilian casualties; political radicalization. Top-band answers compare two specific countries with detailed evidence and analyze the significance of the changes experienced.', 290);

