INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-688', '6. Inter-War Europe & Diplomacy', 'HL', 'P3-EUR', 'The Nazi-Soviet Pact was signed in:', 'August 1938', 'March 1939', 'August 1939', 'September 1939', 2, 'See mark scheme for detailed explanation.', 689);
