INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-691', '6. Inter-War Europe & Diplomacy', 'HL', 'P3-EUR', 'D | 2. B | 3. C | 4. C | 5. B', '', '', '', '', 3, 'See mark scheme for detailed explanation.', 692);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-290', '6. Inter-War Europe & Diplomacy', 'HL', 'short_answer', 'P3-EUR', 15, '"Hitler''s consolidation of power between January 1933 and August 1934 was a political revolution." To what extent do you agree?', 'Revolutionary aspects: destruction of democratic institutions; Enabling Act bypassed constitution; elimination of opposition parties; Night of the Long Knives; combining President and Chancellor roles. Continuity: used existing legal framework; maintained bureaucracy and military; kept capitalist economy; relied on conservative elites initially. Top-band answers assess whether the changes constituted a genuine ''revolution'' or were achieved within existing structures.', 291);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-291', '6. Inter-War Europe & Diplomacy', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the reasons for the rise to power of Mussolini.', 'Reasons: post-war disillusionment and ''mutilated victory''; fear of socialist revolution; weakness of liberal democracy; political instability; Fascist violence and organization; Mussolini''s political skill; support from industrialists and landowners; the March on Rome and King''s capitulation. Top-band answers evaluate the relative importance of structural factors versus Mussolini''s agency.', 292);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-292', '6. Inter-War Europe & Diplomacy', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate social developments in one European country (other than Germany, Italy, or Spain) in the inter-war years.', 'Depending on chosen country, should address: impact of WWI on society; women''s roles; urbanization; cultural changes; impact of economic crises; class relations; education; welfare provision; ethnic/minority issues. Top-band answers provide detailed knowledge of the chosen country and evaluate the significance of social developments within the broader European context.', 293);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-293', '6. Inter-War Europe & Diplomacy', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the reasons for, and the results of, the policy of appeasement.', 'Reasons for: desire to avoid another war; British military unpreparedness; sympathy for German grievances; fear of communism; economic concerns; public opinion. Results: initial territorial concessions to Germany; emboldened Hitler; failed to prevent war; bought time for rearmament (debatable); discredited collective security. Top-band answers evaluate both the rationale and the consequences of appeasement, considering multiple perspectives.', 294);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-294', '6. Inter-War Europe & Diplomacy', 'HL', 'short_answer', 'P3-EUR', 15, '"The Second World War had a devastating impact on the civilian population." Discuss with reference to any two European countries.', 'Should address: bombing of civilians (Blitz, firebombing of Dresden/Hamburg); occupation and resistance; Holocaust; forced labor; displacement and refugees; rationing and economic hardship; psychological impact; collaboration; partisan warfare. Top-band answers provide detailed evidence from two specific countries and analyze the nature and extent of civilian suffering.', 295);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-295', '6. Inter-War Europe & Diplomacy', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the reasons for the failure of the League of Nations to maintain peace in Europe.', 'Structural weaknesses: absence of US, USSR (initially), and later Germany; unanimity requirement; no military force; voluntary membership. Failures: Manchuria (1931); Abyssinia (1935--36); inability to address German rearmament; ignored aggression. Mitigating factors: successes in the 1920s; difficult circumstances; reliance on major powers'' cooperation. Top-band answers evaluate structural versus circumstantial factors.', 296);

