INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-704', '7. Post-War Europe (1945–2000)', 'HL', 'P3-EUR', 'The Hungarian Uprising occurred in:', '1953', '1956', '1968', '1989', 1, 'See mark scheme for detailed explanation.', 705);
