INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-710', '7. Post-War Europe (1945–2000)', 'HL', 'P3-EUR', 'The ECSC was established in:', '1945', '1951', '1957', '1967', 1, 'See mark scheme for detailed explanation.', 711);
