INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-714', '7. Post-War Europe (1945–2000)', 'HL', 'P3-EUR', 'Jean Monnet is best known as:', 'First President of the EU Commission', 'A founding father of European integration', 'The architect of NATO', 'The author of the Maastricht Treaty', 1, 'See mark scheme for detailed explanation.', 715);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p3-mcq-715', '7. Post-War Europe (1945–2000)', 'HL', 'P3-EUR', 'B | 2. C | 3. C | 4. D | 5. B', '', '', '', '', 1, 'See mark scheme for detailed explanation.', 716);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-296', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss political and economic developments in the Soviet Union between 1945 and 1953.', 'Political: post-war Stalinism; renewed purges (Leningrad Affair, Doctors'' Plot); cult of personality intensified; control over Eastern Europe; Cold War tensions. Economic: Fourth Five-Year Plan; reconstruction after war devastation; continued collectivization; focus on heavy industry; nuclear weapons program. Top-band answers link political and economic developments and evaluate their significance.', 297);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-297', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, '"By 1991, Gorbachev''s policies had achieved his aims." To what extent do you agree?', 'Gorbachev''s aims: reform and preserve the Soviet system; economic modernization; political liberalization; improved East-West relations. Achievements: greater freedoms; arms reduction treaties; end of Cold War. Failures: economic decline worsened; nationalist movements fragmented the USSR; loss of Eastern Europe; unintended collapse of the Soviet Union itself. Top-band answers clearly define what Gorbachev intended and evaluate the gap between intentions and outcomes.', 298);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-298', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the impact of Stalin''s domestic policies on the Soviet Union between 1928 and 1941.', 'Economic: rapid industrialization; creation of heavy industrial base; collectivization disrupted agriculture but served state goals. Social: urbanization; mass education; improved healthcare but at cost of personal freedoms; famine deaths. Political: purges eliminated opposition; totalitarian control; cult of personality; terror as governance tool. Top-band answers balance achievements against human costs and evaluate different aspects of impact.', 299);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-299', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the role of Adenauer in Germany''s economic recovery.', 'Adenauer''s contributions: economic liberalization under Erhard; social market economy; integration with Western institutions (NATO, EEC); political stability; Franco-German reconciliation. Other factors: Marshall Plan; currency reform (1948); Korean War boom; cheap labor from refugees; US strategic interest. Top-band answers evaluate Adenauer''s specific role against broader contextual factors.', 300);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-300', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Examine the role of Juan Carlos in Spain''s peaceful transition to democracy.', 'Juan Carlos''s role: chose reformist PM Suarez; supported democratic constitution; refused to support 1981 coup attempt (23-F); symbolized continuity and change; legitimized the transition. Other factors: economic modernization under late Franco; EU aspirations; societal desire for change; Suarez''s political skill; consensus among political parties. Top-band answers evaluate whether Juan Carlos was decisive or facilitated broader processes.', 301);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-301', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the extent of political change in one western or northern European country (other than France, Germany, and Spain) between 1945 and 2000.', 'Depending on the chosen country, should address: post-war political settlement; development of welfare state; evolution of party system; social movements; EU membership and its impact; economic modernization; relationship with Cold War dynamics. Top-band answers provide detailed analysis of their chosen country and evaluate the balance between continuity and change.', 302);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-302', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, '"Protests against Soviet domination in central and eastern Europe were unsuccessful up to 1980." With reference to East Germany and Poland or Hungary and Czechoslovakia, to what extent do you agree?', 'Unsuccessful: all major protests were suppressed (East Germany 1953, Hungary 1956, Czechoslovakia 1968); Soviet control reimposed; no fundamental political change; Brezhnev Doctrine. Partially successful: preserved spirit of resistance; created martyrs and inspiration for later movements; forced limited reforms; demonstrated limits of Soviet power; built civil society. Top-band answers compare two cases in detail and assess degrees of success/failure.', 303);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-303', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Compare and contrast the roles of Walesa in Poland and Havel in Czechoslovakia.', 'Similarities: both led opposition movements; both became presidents; both used non-violent methods; both became international symbols. Differences: Walesa was a trade union leader (worker background) vs Havel as an intellectual/playwright; Solidarity was a mass movement vs Charter 77 as a small dissident group; different timelines of opposition; different paths to power. Top-band answers draw explicit analytical comparisons rather than simply describing each.', 304);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-304', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the political and economic measures undertaken by the Soviet Union to dominate central and eastern Europe between 1945 and 1955.', 'Political: installation of communist governments; purges of non-communists; rigged elections; police state apparatus; personality cults. Economic: COMECON; forced industrialization; collectivization; economic integration with USSR; rejection of Marshall Plan. Top-band answers evaluate both the effectiveness and the consequences of these measures, noting variations between countries.', 305);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-305', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Evaluate the reasons for the emergence of European integration after 1945.', 'Reasons: desire to prevent another European war; economic reconstruction needs; Cold War pressures (US encouragement); shared Franco-German reconciliation interest; economic benefits of larger markets; idealism of European unity. Top-band answers evaluate the relative importance of different motivations and distinguish between economic and political drivers.', 306);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-306', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, '"European integration has been primarily an economic project." To what extent do you agree with this statement?', 'Economic: EEC/Common Market focus; CAP; Single Market; euro. Political: peace project; foreign policy cooperation; democratic conditionality; enlargement as political stabilization. Against purely economic: political motivations from the start (Schuman Declaration); Maastricht''s political union ambitions; security dimension. Top-band answers evaluate both dimensions and their interaction.', 307);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p3-wq-307', '7. Post-War Europe (1945–2000)', 'HL', 'short_answer', 'P3-EUR', 15, 'Discuss the challenges facing European integration between 1980 and 2000.', 'Challenges: British rebate and Euroscepticism; democratic deficit; different visions (federalism vs intergovernmentalism); enlargement strains; CAP reform debates; Maastricht ratification difficulties; national sovereignty concerns; economic divergence; Balkan crises exposing foreign policy weaknesses. Top-band answers analyze multiple challenges and evaluate how successfully they were addressed.', 308);
