INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What were the main types of political organization among indigenous peoples?', 'Non-sedentary (nomadic hunters/gatherers), semi-sedentary (seasonal agriculture), confederations (e.g., Iroquois Confederacy), and empires (Aztec, Inca).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Aztec tribute system?', 'A system where conquered peoples paid tribute in goods, labor, or sacrificial victims to the Aztec Empire, forming the economic foundation of Tenochtitlan.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Inca road system (Qhapaq Nan)?', 'An extensive network of roads spanning over 30,000 km across the Andes, enabling communication, trade, and military movement throughout the Inca Empire.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was quipu?', 'A system of knotted strings used by the Inca for record-keeping, accounting, and communication in the absence of a written language.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was chinampas agriculture?', 'A form of Aztec agriculture using ''floating gardens'' built on lake beds, enabling intensive crop production to feed Tenochtitlan''s large population.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Iroquois Confederacy?', 'A political alliance of five (later six) Native American nations in northeastern North America, known for its sophisticated system of consensus-based governance.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the role of religion in Aztec society?', 'Religion permeated all aspects of Aztec life; rituals including human sacrifice were believed necessary to sustain the cosmos and ensure agricultural fertility.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was mit''a labor?', 'An Inca system of mandatory public service where citizens contributed labor for state projects (roads, temples, military) in exchange for state-provided food and goods.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'Why did Columbus sail west in 1492?', 'Seeking a western sea route to Asia for the Spanish Crown, motivated by trade opportunities, religious zeal, and personal ambition.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the conquest of the Aztecs?', 'Hernan Cortes led a small Spanish force that, with indigenous allies, disease, and superior weapons, conquered the Aztec Empire by 1521.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Columbian Exchange?', 'The transfer of plants (corn, potatoes to Europe; wheat, sugar to Americas), animals (horses, cattle to Americas), and diseases (smallpox to Americas) between hemispheres.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Treaty of Tordesillas (1494)?', 'A papal-mediated agreement dividing newly discovered lands between Spain and Portugal along a meridian in the Atlantic.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the encomienda system?', 'A Spanish colonial labor system granting colonists the right to demand tribute and labor from indigenous people in exchange for ''protection'' and religious instruction.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Law of Burgos (1512)?', 'Spanish laws attempting to regulate the treatment of indigenous peoples, including limits on forced labor, though enforcement was weak.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'How did Pizarro conquer the Inca?', 'Francisco Pizarro exploited the Inca civil war, captured Emperor Atahualpa at Cajamarca (1532), and used disease, military technology, and indigenous divisions to conquer the empire.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the ''Black Legend''?', 'The characterization of Spanish colonization as uniquely cruel, partly based on Bartolome de las Casas''s writings, used by rival colonial powers for propaganda.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the viceroyalty system?', 'Spain''s system of colonial administration where viceroys governed large territories (New Spain, Peru) as representatives of the Spanish Crown.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the cabildo?', 'A colonial Spanish town council that provided local governance and became an important institution for Creole political expression.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was mercantilism in colonial context?', 'The economic policy requiring colonies to trade exclusively with their mother country, serving as sources of raw materials and markets for manufactured goods.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the House of Burgesses?', 'Established in Virginia in 1619, it was the first representative legislative assembly in British North America.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What were the Navigation Acts?', 'British laws (1651 onwards) restricting colonial trade to English/British ships and ports, enforcing mercantilist policies.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was New France''s colonial administration?', 'A centralized system under a governor-general and intendant appointed by the French Crown, with limited local self-governance.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the social hierarchy in Spanish colonies?', 'Peninsulares (Spanish-born) at top, then Creoles (American-born Spanish), Mestizos (mixed), Indigenous peoples, and enslaved Africans at the bottom.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was salutary neglect?', 'The British policy of loosely enforcing trade regulations in the American colonies, allowing them significant self-governance, which ended after 1763.', 24);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the role of the Catholic Church in Spanish colonies?', 'The Church served as a tool of colonization, converting indigenous peoples, establishing missions and schools, and functioning as a major landowner and political force.', 25);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was syncretism?', 'The blending of indigenous religious beliefs and practices with Christianity, creating unique hybrid religious traditions (e.g., Day of the Dead, Vodou).', 26);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'Who were the Jesuits in the Americas?', 'Members of the Society of Jesus who established missions, particularly in South America (Reductions in Paraguay), protecting indigenous peoples while converting them.', 27);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Great Awakening?', 'A series of religious revivals in British North America (1730s--1740s) that increased religious participation, challenged established churches, and promoted individual spiritual experience.', 28);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the role of Puritans in New England?', 'Puritans established colonies (Massachusetts Bay) as religious communities, creating theocratic governance, mandatory church attendance, and strict moral codes.', 29);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What were the Jesuit Reductions?', 'Mission communities in South America (particularly Paraguay) where Jesuits organized indigenous peoples into self-governing agricultural communities with education and healthcare.', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Inquisition in the Americas?', 'The extension of the Catholic Inquisition to the colonies, targeting heresy, crypto-Judaism, and indigenous religious practices, enforcing Catholic orthodoxy.', 31);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was religious tolerance in colonial America?', 'Some colonies (Rhode Island, Pennsylvania, Maryland) offered varying degrees of religious freedom, contrasting with the religious uniformity of other European colonies.', 32);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the triangular trade?', 'A three-leg trading system: manufactured goods from Europe to Africa, enslaved Africans to the Americas (Middle Passage), and raw materials/cash crops back to Europe.', 33);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Middle Passage?', 'The forced transatlantic voyage of enslaved Africans to the Americas, characterized by horrific conditions, with mortality rates of 10--20% or higher.', 34);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the plantation system?', 'Large-scale agricultural operations in the Americas using enslaved labor to produce cash crops (sugar, tobacco, cotton, coffee) for export.', 35);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the Code Noir?', 'A French legal code (1685) regulating slavery in French colonies, defining the status of enslaved people and providing some minimal protections.', 36);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What forms did slave resistance take?', 'Resistance included: work slowdowns, sabotage, maintaining cultural practices, running away (maroon communities), and armed revolts (e.g., Stono Rebellion 1739).', 37);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What were maroon communities?', 'Settlements of escaped enslaved people who formed independent communities in remote areas, particularly in the Caribbean, Brazil, and Suriname.', 38);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'How did slavery differ across colonial systems?', 'Spanish law allowed some paths to freedom; British system was more rigidly racial; French Code Noir was codified but harsh; Portuguese system in Brazil was the largest in the Americas.', 39);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-1', 'What was the economic importance of slavery?', 'Enslaved labor was fundamental to colonial economies, producing sugar, tobacco, cotton, rice, and other commodities that generated enormous wealth for European powers.', 40);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Know the causes of independence movements (intellectual, political, economic, social)', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Understand the American Revolution: causes, course, and outcomes', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Analyze the significance of the Declaration of Independence', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Evaluate the strengths and weaknesses of the Articles of Confederation', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Understand the US Constitution as a ''bundle of compromises''', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Know the causes and course of Latin American independence movements', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Compare the roles of Bolivar and San Martin', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Analyze the Haitian Revolution and its significance', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Evaluate the role of different social classes in independence movements', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Assess the impact of independence on different groups (Creoles, indigenous, enslaved)', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Understand challenges of post-independence nation-building', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Know the concept and examples of caudillismo in Latin America', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Evaluate US westward expansion and Manifest Destiny', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Analyze the Monroe Doctrine and its significance', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Assess the Mexican-American War: causes and consequences', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Understand Canadian Confederation and its causes', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Compare nation-building challenges in the US, Canada, and Latin America', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Evaluate the economic impact of independence on the Americas', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Know Church-State conflicts in post-independence Latin America', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-2', 'Assess the treatment of indigenous peoples during nation-building', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What were the main causes of the American Revolution?', 'Taxation without representation, restriction of colonial self-governance, Enlightenment ideas, British mercantilist policies, and events like the Boston Massacre and Tea Party.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'Who was Simon Bolivar?', 'Venezuelan military and political leader who led independence movements across South America, liberating Venezuela, Colombia, Ecuador, Peru, and Bolivia.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the Declaration of Independence (1776)?', 'A document declaring the American colonies'' separation from Britain, asserting natural rights to life, liberty, and the pursuit of happiness.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the Haitian Revolution (1791--1804)?', 'A successful slave revolt in Saint-Domingue that created Haiti, the first independent Black republic and the only successful large-scale slave revolution in history.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'Who was Jose de San Martin?', 'Argentine general who led independence movements in southern South America, liberating Argentina, Chile, and contributing to Peru''s liberation.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the role of Creoles in Latin American independence?', 'Creoles (American-born people of Spanish descent) led independence movements, motivated by resentment of Peninsular privilege, Enlightenment ideas, and Napoleon''s invasion of Spain.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the Articles of Confederation?', 'The first US governing document (1781--1789), which created a weak central government with limited power over states, eventually replaced by the Constitution.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the US Constitution (1787)?', 'The supreme law of the United States, establishing a federal system with separation of powers (executive, legislative, judicial) and a Bill of Rights (1791).', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was caudillismo?', 'A system of rule by military strongmen (caudillos) common in post-independence Latin America, characterized by personalist authoritarian leadership and regional power bases.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was Manifest Destiny?', 'The 19th-century American belief that the US was destined to expand across the North American continent, justifying territorial expansion westward.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the Monroe Doctrine (1823)?', 'A US foreign policy declaring opposition to European colonization or interference in the Americas, establishing the Western Hemisphere as a US sphere of influence.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the War of 1812?', 'A conflict between the US and Britain (1812--1815) over trade restrictions, impressment of sailors, and territorial disputes, ending in status quo ante bellum.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What were the challenges of nation-building in Latin America?', 'Regional divisions, ethnic tensions, economic dependency, caudillismo, Church-State conflicts, border disputes, and weak institutional frameworks.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the Mexican-American War (1846--1848)?', 'A war resulting in Mexico ceding nearly half its territory (Treaty of Guadalupe Hidalgo), including present-day California, Nevada, Utah, and parts of other states.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was Canadian Confederation (1867)?', 'The union of British North American colonies (Ontario, Quebec, Nova Scotia, New Brunswick) into the Dominion of Canada through the British North America Act.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-2', 'What was the impact of independence on Latin American economies?', 'Economic disruption from wars; continuation of export-dependent economies; foreign debt; British economic influence replacing Spanish; uneven development.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Understand the sectional crisis over slavery (1840s--1860)', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Know key compromises and their failures (Missouri, 1850, Kansas-Nebraska)', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Analyze the significance of the Lincoln-Douglas debates and 1860 election', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Compare Union and Confederate strengths and weaknesses', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Evaluate the military significance of key battles', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Assess the role and significance of the Emancipation Proclamation', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Know the contributions of African Americans during the Civil War', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Understand Presidential vs Congressional Reconstruction', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Evaluate the successes and failures of Reconstruction', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-3', 'Assess the impact of the war and Reconstruction on African Americans', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What was the Compromise of 1850?', 'A package of bills addressing slavery in new territories: California admitted as free state, Fugitive Slave Act strengthened, popular sovereignty in Utah/New Mexico, slave trade abolished in DC.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What were the Lincoln-Douglas Debates (1858)?', 'A series of seven debates between Abraham Lincoln and Stephen Douglas during the Illinois Senate race, focusing on slavery''s expansion, which elevated Lincoln to national prominence.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What was the Emancipation Proclamation (1863)?', 'Lincoln''s executive order declaring enslaved people in Confederate states to be free, transforming the war into a fight against slavery and enabling African American military service.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What was the Battle of Gettysburg (1863)?', 'A turning-point Union victory in Pennsylvania that ended Lee''s invasion of the North and marked the beginning of Confederate military decline.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What was Reconstruction?', 'The period (1865--1877) of rebuilding the South after the Civil War, including efforts to integrate formerly enslaved people into political and economic life.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What were the Black Codes?', 'Laws passed by Southern states (1865--1866) restricting the rights and freedoms of African Americans, attempting to maintain a labor system similar to slavery.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What were the 13th, 14th, and 15th Amendments?', 'Constitutional amendments abolishing slavery (13th), granting citizenship and equal protection (14th), and prohibiting racial discrimination in voting (15th).', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-3', 'What was the significance of the election of 1860?', 'Lincoln''s election on an anti-slavery-expansion platform triggered the secession of Southern states, leading directly to the Civil War.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Understand industrialization and its social impact in the Americas', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Know the causes and consequences of mass immigration', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate the Progressive Era reforms in the US', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Analyze the Porfiriato and causes of the Mexican Revolution', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Assess Canadian westward expansion and nation-building', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Understand the development of labor movements', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Know the impact of Jim Crow on African Americans', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate urbanization and its challenges', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Compare modernization processes across different countries', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Assess the impact of development on indigenous peoples', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Understand US expansionism and the Spanish-American War', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Know the Roosevelt Corollary and its application', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate US intervention in Latin America (Panama, Nicaragua, Haiti, etc.)', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Analyze the construction and significance of the Panama Canal', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Assess the causes and impact of US entry into WWI', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate Wilson''s Fourteen Points and their reception', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Understand US rejection of the League of Nations', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Know Latin American responses to US interventionism', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Assess Canadian involvement in World War I', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate the shift from isolationism to internationalism', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Understand the causes of the Mexican Revolution (Porfiriato, social inequality, political repression)', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Know the key figures and factions (Madero, Zapata, Villa, Carranza, Obregon, Cardenas)', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Analyze the phases of the Revolution (1910--1920)', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate the significance of the 1917 Constitution', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Assess land reform and its implementation', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Understand the role of foreign intervention', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Know the consolidation of the revolutionary state (1920s--1930s)', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate Cardenas''s presidency and its legacy', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Assess the revolution''s impact on different social groups', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-4', 'Evaluate whether the revolution achieved its goals', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Gilded Age?', 'A period (1870s--1900s) of rapid US economic growth marked by industrialization, urbanization, immigration, and stark inequality, with powerful business magnates and political corruption.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Progressive Era?', 'A period of reform (1890s--1920s) addressing the social problems of industrialization, including labor rights, women''s suffrage, trust-busting, and political reform.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Mexican Revolution (1910--1920)?', 'A major armed struggle that overthrew the dictatorship of Porfirio Diaz and led to political, social, and economic reforms, producing the 1917 Constitution.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Porfiriato?', 'The period of Porfirio Diaz''s rule in Mexico (1876--1911), characterized by economic modernization, foreign investment, political authoritarianism, and social inequality.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Canadian Confederation''s expansion?', 'After 1867, Canada expanded westward by acquiring Rupert''s Land, creating new provinces (Manitoba, BC, Saskatchewan, Alberta), and building the transcontinental railway.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the significance of immigration to the Americas?', 'Massive immigration (1880s--1920s) transformed demographics, culture, and economies, providing labor for industrialization while creating social tensions.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What were Jim Crow laws?', 'State and local laws in the US South enforcing racial segregation (1877--1960s), creating a system of legalized discrimination against African Americans.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was Plessy v. Ferguson (1896)?', 'A US Supreme Court decision upholding racial segregation under the ''separate but equal'' doctrine, providing legal justification for Jim Crow laws.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Spanish-American War (1898)?', 'A conflict resulting in US acquisition of Puerto Rico, Guam, and the Philippines, and Cuban independence (under US influence), marking the US emergence as an imperial power.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Roosevelt Corollary (1904)?', 'Theodore Roosevelt''s extension of the Monroe Doctrine, asserting the US right to intervene in Latin American affairs to maintain stability and protect US interests.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was Dollar Diplomacy?', 'President Taft''s foreign policy using financial investment to extend US influence in Latin America and East Asia, replacing military intervention with economic control.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Panama Canal?', 'A waterway constructed by the US (completed 1914) across the Isthmus of Panama, dramatically shortening shipping routes between the Atlantic and Pacific oceans.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the US role in World War I?', 'After initial neutrality, the US entered WWI in 1917 (unrestricted submarine warfare, Zimmermann telegram), providing decisive military and economic resources for Allied victory.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was Wilson''s Fourteen Points?', 'President Wilson''s 1918 peace plan advocating self-determination, free trade, open diplomacy, disarmament, and a League of Nations to prevent future wars.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was US isolationism after WWI?', 'The US Senate rejected the Treaty of Versailles and League membership, returning to a policy of avoiding European entanglements while remaining active in the Americas.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Good Neighbor Policy?', 'FDR''s policy (1933) of non-intervention in Latin American affairs, replacing earlier interventionist approaches and seeking hemispheric cooperation.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'Who was Francisco Madero?', 'A wealthy liberal who led the initial revolt against Diaz in 1910, became president in 1911, but was overthrown and killed in a coup by Huerta in 1913.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'Who was Emiliano Zapata?', 'A revolutionary leader from Morelos who championed land reform for peasants, articulated in his Plan de Ayala (1911), demanding redistribution of hacienda lands.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'Who was Pancho Villa?', 'A revolutionary leader from northern Mexico who commanded the Division del Norte, fighting for social reform and against the Huerta regime and later Carranza.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Constitution of 1917?', 'A progressive document establishing labor rights (Article 123), land reform (Article 27), limits on Church power (Article 130), and national ownership of subsoil resources.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'Who was Lazaro Cardenas?', 'Mexican president (1934--1940) who implemented major land redistribution, nationalized the oil industry (1938), and strengthened labor unions and the revolutionary party.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Plan de Ayala?', 'Zapata''s 1911 plan demanding land redistribution from large haciendas to peasant communities, rejecting Madero''s moderate reform approach.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the Cristero War (1926--1929)?', 'An armed rebellion by Catholic groups against the Mexican government''s anti-clerical policies under the 1917 Constitution.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-4', 'What was the ejido system?', 'A system of communal land ownership restored and expanded during the revolution, particularly under Cardenas, providing land to peasant communities.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Understand the causes of the Great Depression', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Know the impact of the Depression on the US economy and society', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Evaluate FDR''s New Deal: aims, methods, successes, and criticisms', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Assess the impact of the Depression on Latin American countries', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Know the response of Canadian governments to the Depression', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Understand the rise of populist leaders in Latin America', 6);
