INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Compare government responses to the Depression across the Americas', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Assess the long-term political and economic legacy of the Depression', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Know the social impact (unemployment, migration, cultural effects)', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Understand US foreign policy in the 1930s (neutrality to involvement)', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Know the causes and significance of US entry into WWII', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Evaluate the US wartime economy and home front', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Assess the social impact of war (women, minorities, Japanese internment)', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Know Canadian military and industrial contributions', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Understand Latin American involvement in the war effort', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Evaluate the impact of the war on hemispheric relations', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Assess the Manhattan Project and use of atomic weapons', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Know the economic effects of the war across the Americas', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-5', 'Evaluate how WWII transformed the Americas'' global position', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What caused the Wall Street Crash (1929)?', 'Overproduction, speculative bubble in stocks, unequal wealth distribution, weak banking system, overreliance on credit, and declining agricultural prices.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the New Deal?', 'FDR''s program of economic relief, recovery, and reform (1933--1939) including the AAA, NRA, TVA, Social Security, and banking reform.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the impact of the Depression on Latin America?', 'Collapse of commodity prices devastated export economies; political instability; rise of populist and nationalist leaders; import substitution industrialization.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'Who was Getulio Vargas?', 'Brazilian leader (1930--1945, 1951--1954) who came to power during the Depression, modernized the economy, promoted industrialization, and established the Estado Novo dictatorship.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was Import Substitution Industrialization (ISI)?', 'An economic strategy adopted by Latin American countries to develop domestic manufacturing to replace imported goods, stimulated by the Depression''s disruption of trade.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the Dust Bowl?', 'Severe drought and dust storms affecting the US Great Plains (1930s), causing agricultural devastation and mass migration of farmers to California.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'How did Canada respond to the Depression?', 'PM Bennett initially relied on tariffs and limited relief; later, the New Deal-inspired reforms and the creation of the Bank of Canada (1934); social welfare development.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the Social Security Act (1935)?', 'US legislation establishing a system of old-age pensions, unemployment insurance, and welfare benefits, marking a major expansion of the federal government''s role.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was US neutrality legislation?', 'A series of Neutrality Acts (1935--1937) restricting US arms sales and loans to belligerent nations, reflecting isolationist sentiment.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was Lend-Lease?', 'A US program (1941) providing military aid to Allied nations (primarily Britain and the USSR) before official US entry into the war.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the attack on Pearl Harbor?', 'Japan''s surprise military strike on the US naval base in Hawaii on December 7, 1941, bringing the US into World War II.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the Manhattan Project?', 'The secret US-led program that developed the atomic bomb, culminating in the bombings of Hiroshima and Nagasaki in August 1945.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was Japanese-American internment?', 'The forced relocation of approximately 120,000 Japanese Americans to internment camps during WWII, based on racial prejudice and wartime hysteria.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the Bracero Program?', 'A US-Mexico agreement (1942--1964) importing temporary Mexican agricultural workers to address labor shortages during the war.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'How did Canada contribute to WWII?', 'Canada declared war in 1939; contributed significant military forces (Dieppe, D-Day, Italy); major industrial production; conscription crisis (1944).', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-5', 'What was the economic impact of WWII on the Americas?', 'Ended the Depression; massive industrial expansion; women in workforce; technological advances; US emerged as global economic superpower; Latin American commodity boom.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Understand post-war political dynamics in Latin America', 1);
