INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Assess US intervention in Latin America during the Cold War', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Know the Chilean experience: Allende to Pinochet', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Understand military dictatorships and their consequences', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Evaluate the Alliance for Progress', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Assess the role of the military in Latin American politics', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Know key guerrilla movements and revolutionary attempts', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Understand Truman''s domestic and foreign policies', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Evaluate the impact of McCarthyism on American society', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Know Eisenhower''s domestic policies and the New Look', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Assess Kennedy''s and Johnson''s domestic programs', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Evaluate the Watergate scandal and Nixon''s presidency', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Understand the social and cultural impact of the Cold War on the US', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Know key developments in Canadian politics (1945--1982)', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Analyze Quebec nationalism and the Quiet Revolution', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Evaluate Trudeau''s leadership and constitutional reform', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Compare US and Canadian political development in this period', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Understand US Cold War foreign policy (containment, domino theory)', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Know the causes, course, and consequences of the Cuban Missile Crisis', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Evaluate US intervention in Latin America during the Cold War', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Analyze the impact of the Vietnam War on US politics and society', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Assess the impact of the Cold War on domestic policies in the Americas', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Know the role of Canada in the Cold War', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Evaluate detente: causes, features, and limitations', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Understand Operation Condor and its consequences', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Compare Cold War impacts across different American countries', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-6', 'Assess the relationship between the Cold War and human rights', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was populism in Latin America?', 'A political approach appealing to ordinary people against established elites, exemplified by leaders like Peron in Argentina and Vargas in Brazil.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'Who was Juan Peron?', 'Argentine president (1946--1955, 1973--1974) who built a populist movement (Peronism) based on labor support, nationalism, and the charismatic appeal of himself and his wife Eva.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Cuban Revolution (1959)?', 'Fidel Castro''s guerrilla movement that overthrew the Batista dictatorship, establishing a socialist state allied with the Soviet Union.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Alliance for Progress?', 'A US initiative (1961) proposed by JFK to promote economic development and democratic reform in Latin America, intended to counter communist influence.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Chilean coup of 1973?', 'A CIA-backed military coup led by General Pinochet that overthrew the democratically elected socialist president Salvador Allende.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was Liberation Theology?', 'A Catholic theological movement in Latin America (1960s--80s) emphasizing social justice, poverty, and political liberation for the poor.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Dirty War in Argentina?', 'A period of state terrorism (1976--1983) under the military junta that kidnapped, tortured, and killed thousands of suspected dissidents (the ''disappeared'').', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Guatemalan Revolution (1944--1954)?', 'A period of democratic reform under Arevalo and Arbenz, ended by a CIA-backed coup in 1954 that overthrew Arbenz''s land reform program.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Truman Doctrine?', 'The 1947 US policy of providing military and economic aid to countries resisting communist influence, marking the start of containment policy.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was McCarthyism?', 'The anti-communist campaign led by Senator Joseph McCarthy (early 1950s), characterized by accusations, blacklisting, and violations of civil liberties.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Great Society?', 'President Johnson''s domestic program (1964--1968) of social reforms including Medicare, Medicaid, civil rights legislation, and the War on Poverty.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was Watergate?', 'A political scandal involving Nixon administration''s cover-up of a break-in at Democratic headquarters, leading to Nixon''s resignation in 1974.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Quiet Revolution?', 'A period of rapid social and political change in Quebec (1960s), including secularization, expansion of the welfare state, and the rise of Quebec nationalism.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Canadian Bill of Rights (1960)?', 'A federal statute enacted under PM Diefenbaker recognizing fundamental rights and freedoms, a precursor to the 1982 Charter of Rights and Freedoms.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the FLQ Crisis (1970)?', 'A crisis triggered by the kidnapping of two officials by the Front de liberation du Quebec, leading PM Trudeau to invoke the War Measures Act.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Charter of Rights and Freedoms (1982)?', 'A constitutional document guaranteeing fundamental freedoms, democratic rights, mobility rights, legal rights, and equality rights for all Canadians.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was containment?', 'US Cold War strategy of preventing the spread of communism through military, economic, and diplomatic means, articulated by George Kennan.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Cuban Missile Crisis (1962)?', 'A 13-day confrontation between the US and USSR over Soviet missiles in Cuba, the closest the Cold War came to nuclear war, resolved by mutual concessions.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Bay of Pigs invasion (1961)?', 'A failed CIA-backed attempt by Cuban exiles to overthrow Castro''s government, embarrassing the Kennedy administration and pushing Cuba closer to the USSR.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Vietnam War''s impact on the Americas?', 'Massive US military involvement (1965--1973); domestic protest movement; political division; military draft resistance; impact on US foreign policy and society.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was the Eisenhower Doctrine?', 'A policy authorizing US military intervention in the Middle East to counter communist influence, extending containment to the region.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was Operation Condor?', 'A campaign of political repression and state terror coordinated by South American military dictatorships (1970s--80s) with US support, targeting left-wing dissidents.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was detente?', 'A period of reduced Cold War tensions (1969--1979) marked by arms control agreements (SALT I), diplomatic engagement, and reduced confrontation between the US and USSR.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-6', 'What was Canada''s role in the Cold War?', 'NATO member; participated in Korean War; NORAD partnership with US; maintained some independence in foreign policy (e.g., recognition of China); peacekeeping role.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Understand the African American civil rights movement: key events, leaders, strategies', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Know landmark legislation (Civil Rights Act 1964, Voting Rights Act 1965)', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Evaluate the roles of MLK, Malcolm X, and other civil rights leaders', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Assess the Hispanic American movement and Cesar Chavez', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Know indigenous rights movements across the Americas', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Understand the feminist movement and its achievements', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Evaluate youth culture and protests of the 1960s--70s', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Compare civil rights movements across the Americas', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Assess the methods and effectiveness of different protest strategies', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Evaluate the long-term impact of civil rights movements', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Understand Reagan''s domestic and foreign policies', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Know the Iran-Contra affair and its implications', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Evaluate the transitions to democracy in Latin America', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Assess NAFTA: aims, impact, and debates', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Know Clinton''s domestic and foreign policies', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Understand Canadian politics: Mulroney, Chretien, Quebec separatism', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Evaluate the ''Pink Tide'' in Latin American politics', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Assess the impact of 9/11 on the Americas', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Know the economic challenges of the 1980s--90s (debt crisis, neoliberalism)', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-ame-cl-7', 'Evaluate the changing role of the US in the Americas after the Cold War', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was Brown v. Board of Education (1954)?', 'A landmark US Supreme Court decision declaring racial segregation in public schools unconstitutional, overturning ''separate but equal.''', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'Who was Martin Luther King Jr.?', 'The most prominent leader of the US civil rights movement, advocating nonviolent protest, delivering the ''I Have a Dream'' speech (1963), and receiving the Nobel Peace Prize.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the Civil Rights Act of 1964?', 'Landmark US legislation prohibiting discrimination based on race, color, religion, sex, or national origin in public accommodations, employment, and federally funded programs.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'Who was Cesar Chavez?', 'A Mexican-American labor leader who co-founded the National Farm Workers Association, organizing strikes and boycotts to improve conditions for agricultural workers.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the feminist movement in the Americas?', 'A movement advocating for women''s rights, including equal pay, reproductive rights, and political representation, gaining momentum in the 1960s--70s.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the indigenous rights movement?', 'Movements across the Americas advocating for indigenous land rights, cultural preservation, political representation, and self-determination (e.g., AIM in the US).', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the youth counter-culture of the 1960s?', 'A cultural movement rejecting mainstream values, embracing anti-war activism, civil rights, sexual liberation, and experimentation, symbolized by the 1968 protests.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the Voting Rights Act (1965)?', 'US legislation prohibiting racial discrimination in voting, eliminating barriers like literacy tests and poll taxes that had disenfranchised African Americans.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was Reaganomics?', 'President Reagan''s economic policy emphasizing tax cuts, deregulation, reduced social spending, and increased military spending, based on supply-side economics.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the Iran-Contra affair?', 'A political scandal in which the Reagan administration secretly sold arms to Iran and used the proceeds to fund Contra rebels in Nicaragua, violating Congressional prohibitions.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was NAFTA?', 'The North American Free Trade Agreement (1994) creating a free trade zone between the US, Canada, and Mexico, eliminating most tariffs between the three countries.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the transition to democracy in Latin America?', 'In the 1980s--90s, most Latin American countries transitioned from military dictatorships to democratic governance, though challenges remained.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the Quebec sovereignty referendum (1995)?', 'A referendum on Quebec independence that was narrowly defeated (50.58% No, 49.42% Yes), highlighting the ongoing tension of Canadian unity.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was the Falklands War (1982)?', 'A conflict between Argentina and Britain over the Falkland Islands, resulting in British victory and contributing to the fall of Argentina''s military junta.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What were the effects of 9/11 on the Americas?', 'September 11, 2001 attacks led to the War on Terror, invasion of Afghanistan and Iraq, increased security measures, and debates over civil liberties.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-ame-fc-7', 'What was Hugo Chavez''s Bolivarian Revolution?', 'Venezuelan President Chavez''s (1999--2013) left-wing movement promoting socialism, anti-US foreign policy, and regional integration through oil wealth.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the rise and fall of the Carolingian Empire', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Know the key features of the feudal system and its political implications', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Explain the Investiture Controversy and its resolution', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Compare the political development of England and France (750--1500)', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Analyze the relationship between Church and State in medieval Europe', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Evaluate the significance of the Magna Carta', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the role of the Holy Roman Empire', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Know key dynasties: Carolingian, Capetian, Plantagenet, Habsburg', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Assess the impact of the Black Death on political structures', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the concept of divine right and its evolution', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the structure and functioning of the feudal system', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Explain the manorial system and the life of serfs', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Know key agricultural innovations (three-field system, heavy plough, horse collar)', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Analyze the causes and consequences of the Black Death', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Evaluate the growth of towns and trade in medieval Europe', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the role of guilds in medieval economy', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Assess the Commercial Revolution and its impact', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Know the causes and outcomes of the Peasants'' Revolt (1381)', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand medieval social hierarchy: clergy, nobility, peasantry', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Evaluate the decline of feudalism and its causes', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Know the causes of the First Crusade (religious, political, economic motivations)', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the establishment and governance of Crusader States', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Analyze the role of key leaders: Urban II, Godfrey of Bouillon, Saladin, Richard I', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Evaluate the military and strategic aspects of the major Crusades (1st--4th)', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Assess the impact of the Fourth Crusade on the Byzantine Empire', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand Muslim responses to the Crusades', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Evaluate the social and economic consequences of the Crusades for Europe', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Know the cultural and intellectual exchanges resulting from the Crusades', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Assess the religious motivations versus political and economic factors', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-1', 'Understand the decline and fall of the Crusader States', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Carolingian Renaissance?', 'A cultural and intellectual revival under Charlemagne (768--814) that promoted learning, art, and the standardization of Latin script.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'When was Charlemagne crowned Holy Roman Emperor?', 'December 25, 800 CE, by Pope Leo III in Rome.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Investiture Controversy?', 'A conflict between the papacy and secular rulers (1076--1122) over the right to appoint bishops and abbots, resolved by the Concordat of Worms.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'Who was William the Conqueror?', 'Duke of Normandy who invaded England in 1066, winning the Battle of Hastings and establishing Norman rule.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Magna Carta (1215)?', 'A charter signed by King John of England limiting royal power, establishing the principle that the king was subject to law.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the significance of the Golden Bull of 1356?', 'It formalized the election process for the Holy Roman Emperor, establishing seven prince-electors.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'Who were the Capetian dynasty?', 'French royal dynasty (987--1328) that gradually consolidated royal authority over feudal lords and expanded the French kingdom.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the role of the papacy in medieval politics?', 'The papacy claimed spiritual and often temporal authority, intervening in dynastic disputes and legitimizing or challenging rulers.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the feudal system?', 'A hierarchical social structure based on land ownership and obligations: kings granted land to lords, who granted it to vassals in exchange for military service and loyalty.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the manorial system?', 'An economic system where peasants (serfs) worked on a lord''s estate (manor) in exchange for protection and the right to farm small plots for themselves.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Black Death?', 'A devastating plague pandemic (1347--1351) that killed approximately one-third of Europe''s population, causing massive social and economic upheaval.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What were medieval guilds?', 'Associations of craftsmen or merchants that regulated trade, set quality standards, controlled prices, and provided training through apprenticeships.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the three-field system?', 'An agricultural innovation that divided farmland into three sections: one for winter crops, one for spring crops, and one left fallow, increasing productivity.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Commercial Revolution?', 'A period of European economic expansion (11th--13th centuries) marked by increased trade, urbanization, the rise of banking, and new business practices.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the impact of the Black Death on labor?', 'Labor shortages led to higher wages for surviving workers, weakened serfdom, and contributed to peasant revolts (e.g., English Peasants'' Revolt 1381).', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What were the Hanseatic League cities?', 'A commercial confederation of merchant guilds and market towns in northwestern and central Europe, dominating Baltic maritime trade (13th--17th centuries).', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the First Crusade (1096--1099)?', 'A military expedition called by Pope Urban II at the Council of Clermont (1095) to recapture the Holy Land from Muslim control; it succeeded in capturing Jerusalem in 1099.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What were the Crusader States?', 'Four states established after the First Crusade: the Kingdom of Jerusalem, County of Tripoli, Principality of Antioch, and County of Edessa.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'Who was Saladin?', 'Kurdish Muslim leader who united Egypt and Syria, defeated the Crusaders at the Battle of Hattin (1187), and recaptured Jerusalem.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Third Crusade (1189--1192)?', 'Led by Richard I of England, Philip II of France, and Frederick Barbarossa; failed to recapture Jerusalem but secured coastal access for Christian pilgrims.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Fourth Crusade (1202--1204)?', 'Diverted from the Holy Land to sack Constantinople, severely weakening the Byzantine Empire and deepening the East-West Christian schism.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What was the Children''s Crusade (1212)?', 'A popular movement of young people attempting to reach the Holy Land; most participants never arrived, being sold into slavery or turning back.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'What were the long-term effects of the Crusades?', 'Increased East-West trade; transfer of knowledge and technology; weakened Byzantine Empire; strengthened papal authority initially; contributed to rise of Italian maritime cities.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-1', 'When did the last Crusader stronghold fall?', 'Acre fell in 1291, marking the end of Crusader presence in the Holy Land.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Understand the origins of the Renaissance in Italian city-states', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Explain key features of humanism and its impact on thought', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Know major Renaissance artists and their contributions (Leonardo, Michelangelo, Raphael)', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Assess the role of patronage (Medici, papacy) in promoting the Renaissance', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Evaluate the impact of the printing press on European culture', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Compare the Italian Renaissance with the Northern Renaissance', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Understand Machiavelli''s political philosophy and its significance', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Analyze the relationship between wealth, trade, and cultural development', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Assess the impact of the Renaissance on science and education', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Evaluate the extent to which the Renaissance was a ''rebirth'' or a continuation', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Understand the motives for European exploration (economic, religious, technological)', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Know key explorers and their achievements (Columbus, da Gama, Magellan)', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Explain the Treaty of Tordesillas and its implications', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Analyze the Columbian Exchange and its global impact', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Evaluate the impact of European colonization on indigenous peoples', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Understand the development and impact of the Atlantic slave trade', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Assess the role of mercantilism in driving colonial expansion', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Compare Spanish and Portuguese colonial approaches', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Know the establishment of Dutch, English, and French trading empires', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Evaluate the long-term economic and social consequences of exploration', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Understand the causes of the Reformation (theological, political, economic, social)', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Know Luther''s key theological ideas (sola fide, sola scriptura)', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Explain the spread of Protestantism across Europe', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Compare Luther, Calvin, and Zwingli''s theological positions', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Analyze the English Reformation under Henry VIII', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Understand the Counter-Reformation and the Council of Trent', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Evaluate the role of the Jesuits in the Counter-Reformation', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Know the causes, course, and consequences of the Thirty Years'' War', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Assess the significance of the Peace of Westphalia', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-2', 'Evaluate the political, social, and cultural impact of the Reformation', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Renaissance?', 'A cultural, artistic, and intellectual movement originating in 14th-century Italy, characterized by a revival of interest in classical Greek and Roman culture, humanism, and innovation in art and science.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was humanism?', 'An intellectual movement emphasizing the study of classical texts, the importance of human potential and achievement, and a shift from purely theological to secular concerns.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'Who was Lorenzo de'' Medici?', 'Known as ''Lorenzo the Magnificent,'' he was the de facto ruler of Florence (1469--1492) and a major patron of the arts, supporting artists like Michelangelo and Botticelli.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the significance of the printing press (c1440)?', 'Gutenberg''s invention revolutionized communication by enabling mass production of books, spreading ideas rapidly and increasing literacy.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'Who was Niccolo Machiavelli?', 'Florentine political philosopher who wrote ''The Prince'' (1513), advocating pragmatic and sometimes ruthless political leadership.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Northern Renaissance?', 'The spread of Renaissance ideas to Northern Europe (15th--16th centuries), characterized by Christian humanism (Erasmus), detailed realism in art (Van Eyck), and emphasis on religious reform.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the significance of perspective in Renaissance art?', 'The development of linear perspective by Brunelleschi allowed artists to create realistic three-dimensional representations on flat surfaces.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'Who was Erasmus of Rotterdam?', 'Dutch Christian humanist scholar (1466--1536) who advocated Church reform through education and scholarship, writing ''In Praise of Folly.''', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Age of Exploration?', 'A period (15th--17th centuries) when European nations explored and colonized overseas territories, driven by economic, religious, and technological factors.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'Who was Vasco da Gama?', 'Portuguese explorer who reached India by sea in 1498, establishing a direct maritime trade route from Europe to Asia.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Columbian Exchange?', 'The widespread transfer of plants, animals, diseases, culture, and ideas between the Americas and the Old World following Columbus''s 1492 voyage.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Treaty of Tordesillas (1494)?', 'An agreement between Spain and Portugal dividing newly discovered lands outside Europe between them along a meridian in the Atlantic Ocean.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was mercantilism?', 'An economic theory holding that a nation''s wealth was measured by its gold/silver reserves, promoting exports over imports and colonial exploitation.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What were the effects of European diseases on indigenous populations?', 'Diseases like smallpox, measles, and influenza decimated indigenous populations who had no immunity, killing an estimated 90% of the pre-Columbian population in some areas.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the significance of the spice trade?', 'Spices from Asia were hugely valuable in Europe; controlling the spice trade was a primary motivation for Portuguese and Dutch exploration and colonization.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Atlantic slave trade?', 'The forced transportation of millions of Africans to the Americas (16th--19th centuries) to labor on plantations, a key component of the triangular trade system.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What were the 95 Theses?', 'Martin Luther''s list of propositions challenging Catholic practices, particularly the sale of indulgences, posted in 1517, sparking the Protestant Reformation.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Diet of Worms (1521)?', 'An imperial assembly where Martin Luther was asked to recant his writings; he refused, leading to his excommunication and the Edict of Worms declaring him an outlaw.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Peace of Augsburg (1555)?', 'A treaty allowing each German prince to choose either Lutheranism or Catholicism for their territory (cuius regio, eius religio).', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Council of Trent (1545--1563)?', 'A major Catholic Church council that addressed Protestant criticisms by clarifying doctrine, reforming abuses, and strengthening Church discipline.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'Who was John Calvin?', 'French Protestant reformer who established a theocratic government in Geneva and developed the doctrine of predestination; his ideas spread widely as Calvinism.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Thirty Years'' War (1618--1648)?', 'A devastating European conflict initially sparked by religious tensions in the Holy Roman Empire, evolving into a broader political war involving most European powers.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Peace of Westphalia (1648)?', 'Treaties ending the Thirty Years'' War, establishing the principle of state sovereignty and ending the era of religious wars in Europe.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-2', 'What was the Society of Jesus (Jesuits)?', 'A Catholic religious order founded by Ignatius of Loyola in 1540, dedicated to education, missionary work, and counter-reformation efforts.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Understand the theory and practice of absolute monarchy', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Analyze Louis XIV''s reign as a model of absolutism', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Know the key ideas of Enlightenment thinkers (Voltaire, Rousseau, Montesquieu, Locke)', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Evaluate the concept of enlightened despotism (Frederick II, Catherine II, Joseph II)', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Compare absolutism in France, Prussia, Russia, and Austria', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Assess the impact of the Enlightenment on political thought', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Understand the social contract theory and its implications', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Evaluate the English Civil War and Glorious Revolution as alternatives to absolutism', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Know the economic policies of mercantilist absolute monarchs', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Assess the legacy of the Enlightenment for modern political systems', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Understand the causes of the French Revolution (financial crisis, social inequality, Enlightenment ideas)', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Know the key phases: constitutional monarchy, radical republic, Directory, Consulate', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Analyze the significance of key events (Bastille, Tennis Court Oath, execution of Louis XVI)', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Evaluate the Reign of Terror: causes, methods, and consequences', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Understand Napoleon''s rise to power (coup of 18 Brumaire)', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Assess Napoleon''s domestic reforms (Napoleonic Code, education, centralization)', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Evaluate Napoleon''s military campaigns and their impact on Europe', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Know the reasons for Napoleon''s defeat (Russia, coalition warfare, overextension)', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Assess the Congress of Vienna and its legacy', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-3', 'Evaluate the long-term significance of the French Revolution for Europe', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was absolute monarchy?', 'A system of government where the monarch holds supreme authority not restricted by written laws, legislature, or customs; exemplified by Louis XIV of France.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was Louis XIV''s famous declaration?', '''L''Etat, c''est moi'' (''I am the State'') -- symbolizing his belief in absolute royal authority and divine right.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Palace of Versailles?', 'Louis XIV''s grand palace outside Paris, used to control the nobility by requiring their attendance at court, and a symbol of French absolutism.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Enlightenment?', 'An 18th-century intellectual movement emphasizing reason, individualism, and skepticism of traditional authority, with thinkers like Voltaire, Rousseau, and Montesquieu.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was Montesquieu''s separation of powers?', 'The idea that government should be divided into legislative, executive, and judicial branches to prevent tyranny, outlined in ''The Spirit of the Laws'' (1748).', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'Who was Frederick the Great?', 'King of Prussia (1740--1786), an ''enlightened despot'' who modernized the army, reformed the legal system, and promoted religious tolerance and education.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the social contract?', 'The theory (developed by Hobbes, Locke, and Rousseau) that government derives its authority from an agreement among citizens to surrender some freedoms in exchange for social order.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was enlightened despotism?', 'A form of absolute monarchy influenced by Enlightenment ideas, where rulers implemented reforms in education, law, and religious tolerance while retaining power.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What were the Estates-General?', 'A legislative assembly representing the three estates of French society (clergy, nobility, commoners), convened by Louis XVI in May 1789 for the first time since 1614.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the storming of the Bastille?', 'On July 14, 1789, a Parisian crowd attacked the Bastille fortress-prison, symbolizing the beginning of the French Revolution and the fall of royal authority.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Declaration of the Rights of Man (1789)?', 'A document asserting that all men are born free and equal, with rights to liberty, property, security, and resistance to oppression -- a foundational text of the Revolution.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Reign of Terror (1793--1794)?', 'A period of extreme violence led by the Committee of Public Safety under Robespierre, during which approximately 17,000 people were executed.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Napoleonic Code?', 'A comprehensive legal code established by Napoleon in 1804 that enshrined equality before the law, property rights, and secular authority, influencing legal systems worldwide.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Continental System?', 'Napoleon''s trade embargo against Britain (1806), intended to weaken the British economy but which also harmed continental European economies.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was Napoleon''s invasion of Russia (1812)?', 'A disastrous military campaign where Napoleon''s Grande Armee was devastated by Russian scorched-earth tactics, harsh winter, and extended supply lines.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-3', 'What was the Congress of Vienna (1814--1815)?', 'A diplomatic conference that redrew the map of Europe after Napoleon''s defeat, seeking to restore the balance of power and conservative order.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Understand the concept of nationalism and its various forms (liberal, conservative, ethnic)', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Know the impact of the Congress of Vienna on European politics', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Analyze the causes, course, and consequences of the 1848 Revolutions', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Evaluate the role of Metternich in suppressing liberal nationalism', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Understand the relationship between liberalism and nationalism', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Assess the impact of industrialization on political movements', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Know the key events in the development of democracy in Britain', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Evaluate the causes and consequences of the Franco-Prussian War', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Understand the Paris Commune and its significance', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Assess the changing balance of power in Europe 1815--1890', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Understand the political situation in Italy and Germany after the Congress of Vienna', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Compare the roles of Cavour, Garibaldi, and Mazzini in Italian unification', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Evaluate the significance of the Franco-Austrian War (1859) for Italian unification', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Know the stages of German unification under Bismarck', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Analyze Bismarck''s use of war as a tool of diplomacy', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Assess the role of the Zollverein in German unification', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Compare ''top-down'' vs ''bottom-up'' approaches to unification', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Evaluate Bismarck''s domestic policies (Kulturkampf, anti-socialist laws, welfare state)', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Understand the problems facing unified Italy and Germany', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-4', 'Compare and contrast the processes of Italian and German unification', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was nationalism in the 19th century?', 'The belief that each nation (defined by shared language, culture, or ethnicity) should have its own sovereign state, driving unification and independence movements across Europe.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What were the Revolutions of 1848?', 'A wave of liberal and nationalist revolutions across Europe (France, German states, Italian states, Austrian Empire) that initially succeeded but were largely suppressed by 1849.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the Concert of Europe?', 'A system of diplomatic cooperation among the Great Powers (Britain, France, Austria, Prussia, Russia) established after the Congress of Vienna to maintain the balance of power.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'Who was Metternich?', 'Austrian chancellor (1809--1848) who dominated European diplomacy, suppressing liberal and nationalist movements to preserve the conservative order.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the Springtime of Peoples?', 'Another name for the 1848 Revolutions, reflecting the widespread hope that liberal and nationalist ideals would transform European politics.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the impact of industrialization on nationalism?', 'Industrialization created new middle and working classes who demanded political representation, while improved communications and transport strengthened national consciousness.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the Paris Commune (1871)?', 'A radical socialist and revolutionary government that briefly ruled Paris (March--May 1871) before being violently suppressed by the French government.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the significance of the Franco-Prussian War (1870--1871)?', 'It completed German unification under Prussian leadership, established the German Empire, and shifted the European balance of power.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the Risorgimento?', 'The Italian unification movement (19th century) that united the various Italian states into a single Kingdom of Italy, completed in 1871 with the capture of Rome.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'Who was Cavour?', 'Count Camillo di Cavour, Prime Minister of Piedmont-Sardinia, who used diplomacy, modernization, and alliance with France to drive Italian unification.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'Who was Garibaldi?', 'An Italian nationalist and military leader who led the ''Expedition of the Thousand'' (1860), conquering Sicily and southern Italy and handing them to King Victor Emmanuel II.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'Who was Otto von Bismarck?', 'Minister-President of Prussia who unified Germany through ''blood and iron'' -- three wars (Danish, Austro-Prussian, Franco-Prussian) and skilled diplomacy.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the Ems Dispatch?', 'A telegram edited by Bismarck in 1870 to provoke France into declaring war on Prussia, leading to the Franco-Prussian War and German unification.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the Zollverein?', 'A customs union of German states (established 1834) that promoted economic integration and Prussian leadership, laying groundwork for political unification.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was Bismarck''s Kulturkampf?', 'Bismarck''s campaign (1871--1878) against Catholic Church influence in Germany, including laws restricting clergy''s political activities and control over education.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-4', 'What was the proclamation of the German Empire?', 'On January 18, 1871, at the Palace of Versailles, King Wilhelm I of Prussia was proclaimed Kaiser (Emperor) of the unified German Empire.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Understand Russia''s social and political conditions under Alexander II', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Evaluate the significance of the emancipation of serfs (1861)', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Know the policies and impact of Alexander III''s counter-reforms', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Analyze the causes and consequences of the 1905 Revolution', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Evaluate Stolypin''s reforms and their effectiveness', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Understand the causes of the February Revolution (1917)', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Assess the failure of the Provisional Government', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Analyze the Bolshevik seizure of power (October Revolution)', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Evaluate Lenin''s domestic policies (War Communism, NEP)', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Understand the Russian Civil War and its consequences', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Understand the long-term causes of WWI (alliance system, imperialism, militarism, nationalism)', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Analyze the short-term causes (Balkan crises, assassination, July Crisis)', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Evaluate the debate over war guilt (Fischer thesis)', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Know the major campaigns and battles on all fronts', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Assess the impact of technology on warfare (machine guns, gas, tanks, aircraft)', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Evaluate the impact of WWI on civilian populations', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Understand the role of propaganda and censorship', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Analyze the factors leading to Allied victory (US entry, German domestic collapse)', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Assess the significance of the Eastern Front', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-5', 'Evaluate the war''s impact on European politics and society', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What were the Great Reforms of Alexander II?', 'A series of reforms including the emancipation of serfs (1861), judicial reform, local government reform (zemstvo), and military reform, aimed at modernizing Russia.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was Bloody Sunday (1905)?', 'On January 22, 1905, tsarist troops fired on peaceful demonstrators in St. Petersburg, sparking the 1905 Revolution and leading to the creation of the Duma.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the October Manifesto (1905)?', 'Tsar Nicholas II''s concession granting civil liberties and establishing the Duma (parliament), issued to end the 1905 Revolution.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the February Revolution (1917)?', 'A spontaneous uprising in Petrograd that forced Tsar Nicholas II to abdicate, ending the Romanov dynasty and establishing the Provisional Government.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the October Revolution (1917)?', 'The Bolshevik seizure of power led by Lenin, overthrowing the Provisional Government and establishing a socialist state.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was War Communism?', 'Bolshevik economic policy during the Russian Civil War (1918--1921): nationalization of industry, grain requisitioning, and centralized control to support the war effort.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the New Economic Policy (NEP)?', 'Lenin''s economic policy (1921--1928) reintroducing limited private enterprise and free trade to revive the economy after the devastation of War Communism.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the Treaty of Brest-Litovsk (1918)?', 'A peace treaty between Soviet Russia and the Central Powers, in which Russia surrendered significant territory to exit World War I.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the Alliance System before WWI?', 'Europe was divided into two alliance blocs: the Triple Alliance (Germany, Austria-Hungary, Italy) and the Triple Entente (France, Russia, Britain).', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the July Crisis of 1914?', 'The diplomatic crisis following the assassination of Archduke Franz Ferdinand that escalated through the alliance system into a full-scale European war within weeks.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the Schlieffen Plan?', 'Germany''s military strategy to quickly defeat France through Belgium before turning to fight Russia, designed to avoid a two-front war; it failed in 1914.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was trench warfare?', 'A form of warfare on the Western Front where opposing armies fought from elaborate systems of trenches, resulting in a bloody stalemate with massive casualties.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the Battle of the Somme (1916)?', 'A major Allied offensive on the Western Front that resulted in over one million casualties for minimal territorial gains, symbolizing the futility of trench warfare.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was unrestricted submarine warfare?', 'Germany''s policy of sinking all ships (including neutral ones) in waters around Britain, a key factor in drawing the United States into the war in 1917.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the impact of WWI on civilians?', 'Total war affected civilians through rationing, conscription, propaganda, bombing of civilian areas, economic hardship, and the mobilization of women into the workforce.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-5', 'What was the Armistice of November 11, 1918?', 'The agreement that ended fighting on the Western Front, signed at 11 AM on November 11, 1918, effectively ending World War I.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Understand the challenges facing Weimar Germany (1918--1933)', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Analyze Hitler''s rise to power and consolidation (1929--1934)', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Evaluate Nazi domestic policies (economic, social, political, racial)', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Know the nature of the Nazi state and extent of resistance', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Analyze Mussolini''s rise to power and consolidation in Italy', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Evaluate Fascist Italy''s domestic policies', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Understand the causes and course of the Spanish Civil War', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Assess political developments in one other European country (e.g., France, USSR)', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Compare and contrast Hitler''s and Mussolini''s regimes', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Evaluate the impact of the Great Depression on European politics', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Understand the aims, terms, and impact of the Paris Peace Settlements', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Evaluate the successes and failures of the League of Nations', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Know the key diplomatic agreements of the 1920s (Dawes Plan, Locarno, Kellogg-Briand)', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Analyze Italian and German foreign policies (1919--1941)', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Evaluate the policy of appeasement: aims, methods, effectiveness', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Understand the Munich Crisis and its consequences', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Assess the causes of the Second World War', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Know the development of European conflict (1939--1941)', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Evaluate the wartime alliance (1941--1945) and reasons for Allied victory', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-6', 'Assess the impact of WWII on civilian populations', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Weimar Republic?', 'Germany''s democratic government (1918--1933), established after WWI, which faced challenges including hyperinflation, political extremism, and the Great Depression.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Stresemann Era (1924--1929)?', 'A period of relative stability in Weimar Germany under Gustav Stresemann''s influence, featuring economic recovery (Dawes Plan), international reconciliation (Locarno), and cultural flourishing.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the March on Rome (1922)?', 'Mussolini''s Fascist march on Rome that pressured King Victor Emmanuel III to appoint Mussolini as Prime Minister, beginning Fascist rule in Italy.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Enabling Act (1933)?', 'A law passed by the German Reichstag giving Hitler dictatorial powers, effectively ending the Weimar Republic and establishing the Nazi dictatorship.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Spanish Civil War (1936--1939)?', 'A conflict between Republican (left-wing) and Nationalist (right-wing, led by Franco) forces, which became a proxy war for European ideological conflicts.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Night of the Long Knives (1934)?', 'Hitler''s purge of the SA leadership and political opponents on June 30, 1934, consolidating his control over the Nazi party and the German military.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was Mussolini''s Corporate State?', 'Mussolini''s economic system organizing Italian society into corporations representing employers and workers, supposedly ending class conflict under Fascist authority.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Reichstag Fire (1933)?', 'The burning of the German parliament building on February 27, 1933, which Hitler used as a pretext to suspend civil liberties and persecute political opponents.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What were the key terms of the Treaty of Versailles (1919)?', 'War guilt clause (Article 231); reparations of 132 billion gold marks; military restrictions; territorial losses (Alsace-Lorraine, Polish Corridor); League of Nations created.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the policy of appeasement?', 'The British and French policy of making concessions to aggressive powers (particularly Nazi Germany) to avoid war, most notably at the Munich Conference (1938).', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Munich Agreement (1938)?', 'An agreement allowing Germany to annex the Sudetenland from Czechoslovakia, hailed by Chamberlain as bringing ''peace for our time'' but widely seen as a failure of appeasement.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Nazi-Soviet Pact (1939)?', 'A non-aggression treaty between Nazi Germany and the Soviet Union (August 1939) with a secret protocol dividing Eastern Europe, enabling Germany''s invasion of Poland.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the League of Nations?', 'An international organization created after WWI to maintain peace through collective security; it was weakened by the absence of the US and inability to enforce decisions.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What were the Locarno Treaties (1925)?', 'Agreements guaranteeing Germany''s western borders with France and Belgium, promoting reconciliation and enabling Germany''s entry to the League of Nations.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was collective security?', 'The principle that aggression against one state would be met by a collective response from all members, the basis of the League of Nations system.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-6', 'What was the Stresa Front (1935)?', 'An agreement between Britain, France, and Italy opposing German rearmament and affirming Locarno Treaty commitments, which quickly collapsed over the Abyssinia Crisis.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand Stalin''s consolidation of power after Lenin''s death', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the Five-Year Plans: aims, methods, results', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess the impact of collectivization and the famine', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Analyze the Great Purges and their impact on Soviet society', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Know Khrushchev''s domestic and foreign policies', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate Brezhnev''s era of ''stagnation''', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand Gorbachev''s reforms (glasnost, perestroika)', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Analyze the causes and consequences of the collapse of the Soviet Union', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess post-Soviet Russia under Yeltsin (1991--2000)', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the extent of political, social, and economic change 1924--2000', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand the impact of WWII on Western Europe and post-war reconstruction', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the Marshall Plan and its economic and political impact', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Analyze Adenauer''s role in West Germany''s recovery and integration', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess de Gaulle''s domestic and foreign policies', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Know the development of European integration (ECSC, EEC, EU)', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate Spain''s transition to democracy after Franco', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand the development of the welfare state', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Analyze the social and cultural changes of the 1960s', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess German reunification: process, challenges, consequences', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate political developments in one other Western/Northern European country', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand how Soviet control was established in Eastern Europe after 1945', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Know the mechanisms of Soviet domination (COMECON, Warsaw Pact, political control)', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Analyze protests against Soviet control (1953, 1956, 1968, 1980--81)', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the role of Solidarity in Poland''s democratic transition', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand the revolutions of 1989 and the collapse of communism', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess the role of Gorbachev in ending Soviet control', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Know the causes, course, and consequences of the Balkan conflicts', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the transition from communism: economic and political challenges', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Compare the experiences of different Eastern European countries', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess the significance of EU and NATO enlargement for the region', 30);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand the origins of European integration (post-war reconstruction, Cold War context)', 31);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Know the key treaties and institutions (ECSC, EEC, EU, Maastricht)', 32);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the role of key figures (Monnet, Schuman, Adenauer, de Gaulle)', 33);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess the development of the Common Agricultural Policy', 34);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand the enlargement process and its challenges', 35);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the debates over sovereignty and supranationalism', 36);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Know the creation and impact of the euro', 37);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Assess the democratic deficit debate', 38);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Understand the impact of integration on member states', 39);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p3-eur-cl-7', 'Evaluate the successes and failures of European integration by 2000', 40);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What were Stalin''s Five-Year Plans?', 'A series of centralized economic plans (beginning 1928) focused on rapid industrialization, transforming the USSR into a major industrial power through state-controlled production targets.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was collectivization?', 'Stalin''s policy of consolidating individual peasant farms into large state-run collective farms (kolkhozes), causing widespread famine and resistance, particularly in Ukraine (Holodomor).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What were the Great Purges (1936--1938)?', 'Stalin''s campaign of political repression involving show trials, imprisonment, and execution of perceived enemies, eliminating potential rivals and creating an atmosphere of terror.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was de-Stalinization?', 'Khrushchev''s policy of dismantling aspects of Stalin''s legacy, including his ''Secret Speech'' (1956) denouncing Stalin''s cult of personality and abuses of power.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was Glasnost?', 'Gorbachev''s policy of ''openness'' (1985--1991), allowing greater freedom of speech, press, and political expression in the Soviet Union.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was Perestroika?', 'Gorbachev''s policy of economic ''restructuring'' (1985--1991), introducing market-oriented reforms to the Soviet planned economy.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What caused the collapse of the Soviet Union (1991)?', 'A combination of economic stagnation, nationalist movements in republics, Gorbachev''s reforms weakening central control, failed August coup, and rise of Yeltsin.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Brezhnev Doctrine?', 'The policy that the Soviet Union would intervene in any socialist country threatened by internal or external forces hostile to socialism, used to justify the invasion of Czechoslovakia (1968).', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Marshall Plan?', 'The US economic aid program (1948--1952) providing approximately $13 billion to help rebuild Western European economies after WWII, also intended to prevent communist expansion.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'Who was Konrad Adenauer?', 'First Chancellor of West Germany (1949--1963), who oversaw the ''economic miracle'' (Wirtschaftswunder), NATO membership, and reconciliation with France.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the European Economic Community (EEC)?', 'An economic union established by the Treaty of Rome (1957), initially comprising six countries, promoting economic integration through a common market.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'Who was Charles de Gaulle?', 'French President (1959--1969) who established the Fifth Republic, pursued an independent foreign policy, withdrew France from NATO''s military command, and vetoed British EEC membership.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the German ''economic miracle'' (Wirtschaftswunder)?', 'West Germany''s rapid economic recovery and growth in the 1950s--60s, driven by Marshall Plan aid, currency reform, social market economy, and industrial modernization.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the transition to democracy in Spain?', 'Following Franco''s death (1975), King Juan Carlos and PM Adolfo Suarez guided Spain''s peaceful transition to parliamentary democracy, culminating in the 1978 constitution.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was German reunification?', 'The process of merging East and West Germany following the fall of the Berlin Wall (1989), formally completed on October 3, 1990, under Chancellor Helmut Kohl.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the welfare state in post-war Europe?', 'Government systems providing healthcare, education, unemployment insurance, and pensions to citizens, expanded significantly in Western Europe after 1945.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Iron Curtain?', 'A term used by Winston Churchill (1946) to describe the political and ideological divide separating Soviet-controlled Eastern Europe from Western Europe during the Cold War.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Warsaw Pact?', 'A military alliance of Soviet bloc nations (1955--1991), created as a response to NATO and serving as a mechanism for Soviet control over Eastern Europe.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Hungarian Uprising (1956)?', 'A popular revolt in Hungary against Soviet-imposed policies, briefly establishing a reformist government under Nagy before being crushed by Soviet military intervention.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Prague Spring (1968)?', 'A period of political liberalization in Czechoslovakia under Dubcek (''socialism with a human face''), ended by Warsaw Pact invasion in August 1968.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was Solidarity?', 'A Polish trade union movement led by Lech Walesa (1980s) that became a powerful anti-communist political force, playing a key role in the end of communist rule in Poland.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the fall of the Berlin Wall?', 'On November 9, 1989, East German authorities opened the Berlin Wall, symbolizing the collapse of communism in Eastern Europe and leading to German reunification.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What were the Balkan conflicts of the 1990s?', 'A series of wars following Yugoslavia''s dissolution, including conflicts in Slovenia, Croatia, Bosnia (including Srebrenica massacre), and Kosovo, marked by ethnic cleansing.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'Who was Vaclav Havel?', 'Czech dissident playwright who became the first president of post-communist Czechoslovakia (1989) and later the Czech Republic, symbolizing the Velvet Revolution.', 24);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the European Coal and Steel Community (ECSC)?', 'Founded in 1951 by six nations (France, Germany, Italy, Belgium, Netherlands, Luxembourg), it pooled coal and steel resources to promote economic cooperation and prevent war.', 25);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Maastricht Treaty (1992)?', 'The treaty that created the European Union, establishing common foreign and security policy, justice and home affairs cooperation, and the path to a common currency (euro).', 26);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Schengen Agreement?', 'An agreement (1985, implemented 1995) creating a zone of free movement across participating European countries by eliminating border controls.', 27);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What is the euro?', 'The common currency adopted by EU member states in the eurozone, introduced as an electronic currency in 1999 and as physical notes and coins in 2002.', 28);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the Single European Act (1986)?', 'An amendment to the Treaty of Rome that set the goal of establishing a single internal market by 1992, removing barriers to the free movement of goods, services, capital, and people.', 29);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'Who was Jean Monnet?', 'A French political economist considered one of the founding fathers of European integration, who proposed the ECSC and championed supranational cooperation.', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What was the European Parliament?', 'The directly elected legislative body of the EU (direct elections since 1979), representing EU citizens and sharing legislative power with the Council of the EU.', 31);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p3-eur-fc-7', 'What were the Copenhagen Criteria (1993)?', 'Conditions for EU membership including stable democratic institutions, functioning market economy, and ability to take on obligations of membership, used for Eastern European enlargement.', 32);
